im); lim.connect(ac.destination);\n    masterAn=ac.createAnalyser(); masterAn.fftSize=256; masterAn._buf=new Float32Array(masterAn.fftSize); lim.connect(masterAn);\n    const revIn=ac.createGain(),conv=ac.createConvolver(),revRet=ac.createGain(); conv.buffer=makeImpulse(state.fx.revSize); revRet.gain.value=state.fx.revMix;\n    revIn.connect(conv); conv.connect(revRet); revRet.connect(masterGain);\n    const dlyIn=ac.createGain(),dly=ac.createDelay(1.5),dfb=ac.createGain(),dlyRet=ac.createGain(); dly.delayTime.value=state.fx.dlyTime; dfb.gain.value=state.fx.dlyFb; dlyRet.gain.value=state.fx.dlyMix;\n    dlyIn.connect(dly); dly.connect(dfb); dfb.connect(dly); dly.connect(dlyRet); dlyRet.connect(masterGain);\n    fxRack={revIn,conv,revRet,dlyIn,dly,dfb,dlyRet};\n    for(let i=0;i<24;i++){\n      const trim=ac.createGain();\n      const hpf=ac.createBiquadFilter();hpf.type=\"highpass\";hpf.frequency.value=20;hpf.Q.value=0.707;\n      const eq0=ac.createBiquadFilter();eq0.type=\"lowshelf\";const eq1=ac.createBiquadFilter();eq1.type=\"peaking\";\n      const eq2=ac.createBiquadFilter();eq2.type=\"peaking\";const eq3=ac.createBiquadFilter();eq3.type=\"highshelf\";\n      const lpf=ac.createBiquadFilter();lpf.type=\"lowpass\";lpf.frequency.value=20000;lpf.Q.value=0.707;\n      const preAn=ac.createAnalyser();preAn.fftSize=256;\n      const gate=ac.createGain();gate.gain.value=1;\n      const comp=ac.createDynamicsCompressor();comp.threshold.value=0;comp.ratio.value=1;comp.attack.value=0.005;comp.release.value=0.15;comp.knee.value=0;\n      const mk=ac.createGain();mk.gain.value=1; const fdr=ac.createGain();fdr.gain.value=0; const pan=ac.createStereoPanner();\n      const an=ac.createAnalyser();an.fftSize=256; const revSend=ac.createGain();revSend.gain.value=0; const dlySend=ac.createGain();dlySend.gain.value=0;\n      trim.connect(hpf);hpf.connect(eq0);eq0.connect(eq1);eq1.connect(eq2);eq2.connect(eq3);eq3.connect(lpf);\n      lpf.connect(preAn);lpf.connect(gate);gate.connect(comp);comp.connect(mk);mk.connect(fdr);\n      fdr.connect(pan);pan.connect(masterGain);fdr.connect(an);\n      fdr.connect(revSend);revSend.connect(revIn);fdr.connect(dlySend);dlySend.connect(dlyIn);\n      aNodes[i]={trim,hpf,eq:[eq0,eq1,eq2,eq3],lpf,preAn,preBuf:new Float32Array(preAn.fftSize),gate,comp,mk,fdr,pan,an,buf:new Float32Array(an.fftSize),revSend,dlySend};\n    }\n    for(let i=0;i<24;i++) applyChanAudio(i);\n  }\n  applyChanAudio=function(i){\n    if(!ac||!aNodes[i])return; const n=aNodes[i],c=CH[i],t=ac.currentTime;\n    n.trim.gain.setTargetAtTime(dbToLin(c.gain-16)*(c.phase?-1:1),t,0.02);\n    n.hpf.frequency.setTargetAtTime(c.hpfOn?c.hpf:20,t,0.02);\n    n.lpf.frequency.setTargetAtTime(c.lpfOn?c.lpf:20000,t,0.02);\n    const kf=eqTypeFactor(c.eqType);\n    c.eq.forEach((b,bi)=>{ const f=n.eq[bi]; if(f.type!==b.type)f.type=b.type; f.frequency.setTargetAtTime(clamp(b.f,20,20000),t,0.02); f.gain.setTargetAtTime(b.g,t,0.02); f.Q.setTargetAtTime(clamp(b.q*kf,0.05,18),t,0.02); });\n    if(c.compOn){ n.comp.threshold.value=c.compThr; n.comp.ratio.value=(c.compRatio>=40?20:Math.max(1,c.compRatio)); n.comp.attack.value=clamp(c.compAtk/1000,0,0.12); n.comp.release.value=clamp(c.compRel/1000,0.005,1.5); n.comp.knee.value=(c.compKnee===''HARD''||c.compKnee===0)?0:clamp(c.compKnee*4,0,30); n.mk.gain.setTargetAtTime(dbToLin(c.compGain),t,0.02); }\n    else { n.comp.threshold.value=0; n.comp.ratio.value=1; n.mk.gain.setTargetAtTime(1,t,0.02); }\n    n.pan.pan.setTargetAtTime(clamp(c.pan/63,-1,1),t,0.02);\n    let dcaLin=1,muted=false;\n    for(let g=0;g<N_DCA;g++){ if(c.dca[g]){ if(!state.dcaOn[g])muted=true; dcaLin*=dbToLin(state.dcaGain[g]); } }\n    for(let g=0;g<N_MUTE;g++){ if(c.mute[g]&&state.muteActive[g])muted=true; }\n    const soloMuted = anyCue() && !c.cue;\n    const audible=c.on&&!muted&&!soloMuted&&c.fader>FMIN&&c.hasAudio;\n    n.fdr.gain.setTargetAtTime(audible?dbToLin(c.fader)*dcaLin:0,t,0.02);\n    n.revSend.gain.setTargetAtTime((c.hasAudio&&c.fxRev>FMIN)?dbToLin(c.fxRev):0,t,0.02);\n    n.dlySend.gain.setTargetAtTime((c.hasAudio&&c.fxDly>FMIN)?dbToLin(c.fxDly):0,t,0.02);\n  };\n  function applyFX(){ if(!ac||!fxRack)return; const t=ac.currentTime; fxRack.revRet.gain.setTargetAtTime(state.fx.revMix,t,0.03); fxRack.dly.delayTime.setTargetAtTime(clamp(state.fx.dlyTime,0,1.5),t,0.03); fxRack.dfb.gain.setTargetAtTime(clamp(state.fx.dlyFb,0,0.9),t,0.03); fxRack.dlyRet.gain.setTargetAtTime(state.fx.dlyMix,t,0.03); }\n  function processGates(){ if(!ac)return; const t=ac.currentTime;\n    for(let i=0;i<24;i++){ const n=aNodes[i],c=CH[i]; if(!n)continue;\n      if(!c.gateOn||!playing||!c.hasAudio){ n.gate.gain.setTargetAtTime(1,t,0.01); c._gr=0; continue; }\n      n.preAn.getFloatTimeDomainData(n.preBuf); let s=0; for(let k=0;k<n.preBuf.length;k++)s+=n.preBuf[k]*n.preBuf[k];\n      const rms=Math.sqrt(s/n.preBuf.length),db=rms>1e-5?20*Math.log10(rms):-90; const open=db>c.gateThr,target=open?1:dbToLin(c.gateRange);\n      const tc=Math.max(0.004,(open?c.gateAtk:c.gateDecay)/1000/3); n.gate.gain.setTargetAtTime(target,t,tc); c._gr=open?0:Math.max(0,-c.gateRange); }\n  }\n  function applyMasterAudio(){ if(ac&&masterGain){ masterGain.gain.setTargetAtTime(dbToLin(state.master),ac.currentTime,0.02); monoTrim.gain.setTargetAtTime(dbToLin(state.mono),ac.currentTime,0.02); } }\n  applyMonitor=function(){ /* monitor bus is didactic; dim lowers master monitor feel */ };\n  function snapCh(c){ return JSON.parse(JSON.stringify({gain:c.gain,phase:c.phase,phantom:c.phantom,hpfOn:c.hpfOn,hpf:c.hpf,lpfOn:c.lpfOn,lpf:c.lpf,eq:c.eq,eqType:c.eqType,gateOn:c.gateOn,gateThr:c.gateThr,gateRange:c.gateRange,gateAtk:c.gateAtk,gateHold:c.gateHold,gateDecay:c.gateDecay,compOn:c.compOn,compThr:c.compThr,compRatio:c.compRatio,compAtk:c.compAtk,compRel:c.compRel,compKnee:c.compKnee,compGain:c.compGain,pan:c.pan,fader:c.fader,on:c.on,sends:c.sends,sendOn:c.sendOn,sendPre:c.sendPre,dca:c.dca,mute:c.mute,fxRev:c.fxRev,fxDly:c.fxDly})); }\n  function storeScene(slot){ scenes[slot]={ ch:CH.map(snapCh), master:state.master, mono:state.mono, dcaGain:state.dcaGain.slice(), dcaOn:state.dcaOn.slice(), muteActive:state.muteActive.slice(), fx:JSON.parse(JSON.stringify(state.fx)), ts:Date.now() }; toast(\"Cena \"+(slot+1)+\" <b>armazenada</b> ✔\"); }\n  function recallScene(slot){ const s=scenes[slot]; if(!s){ toast(\"Cena \"+(slot+1)+\" vazia\"); return; }\n    s.ch.forEach((sc,i)=>Object.assign(CH[i],JSON.parse(JSON.stringify(sc)))); state.master=s.master; if(s.mono!=null)state.mono=s.mono;\n    state.dcaGain=s.dcaGain.slice(); state.dcaOn=s.dcaOn.slice(); state.muteActive=s.muteActive.slice(); state.fx=JSON.parse(JSON.stringify(s.fx));\n    if(fxRack)fxRack.conv.buffer=makeImpulse(state.fx.revSize);\n    for(let i=0;i<24;i++)applyChanAudio(i); applyMasterAudio(); applyFX();\n    paintBay(); paintSelected(); paintRightRack(); drawScreen(); toast(\"Cena \"+(slot+1)+\" <b>recuperada</b> ▸ faders atualizados\"); }\n  function chLevelDb(i){ if(!ac||!aNodes[i])return -90; const n=aNodes[i]; n.an.getFloatTimeDomainData(n.buf); let s=0; for(let k=0;k<n.buf.length;k++)s+=n.buf[k]*n.buf[k]; const rms=Math.sqrt(s/n.buf.length); return rms>1e-5?20*Math.log10(rms):-90; }\n  function masterLevelDb(){ if(!masterAn)return -90; masterAn.getFloatTimeDomainData(masterAn._buf); let s=0; for(let k=0;k<masterAn._buf.length;k++)s+=masterAn._buf[k]*masterAn._buf[k]; const rms=Math.sqrt(s/masterAn._buf.length); return rms>1e-5?20*Math.log10(rms):-90; }\n  async function loadBuf(url){ if(bufCache[url])return bufCache[url]; const r=await fetch(url); if(!r.ok)throw new Error(\"HTTP \"+r.status); const ab=await r.arrayBuffer(); const b=await ac.decodeAudioData(ab); bufCache[url]=b; return b; }\n  function setStatus(txt,col){ const el=$(\"#audioStatus\"); if(el){ el.textContent=\"áudio: \"+txt; el.style.color=col||\"var(--muted)\"; } }\n  function loadSong(idx){ curSong=idx; const song=SONGS[idx];\n    for(let i=0;i<24;i++){ const st=song.stems[i],c=CH[i];\n      if(st){ c.name=st.n; c.color=st.c; c.file=st.f; c.pan=st.p; c.hpfOn=st.h; c.hpf=st.h?100:80; c.hasAudio=true; c.on=true; c.fader=-3; c.gain=16; c.phase=false; c.phantom=false; }\n      else { c.name=\"—\"; c.color=\"#334155\"; c.file=null; c.hasAudio=false; c.on=false; } }\n    buildBay(); paintBay(); paintSelected(); paintRightRack(); drawScreen(); if(ac){ for(let i=0;i<24;i++)applyChanAudio(i); } }\n  function setPlayBtn(on){ const b=$(\"#playBtn\"); if(b){ b.textContent=on?\"⏸ Parar\":\"► Tocar base\"; b.style.background=on?\"#e0483f\":\"#22b866\"; } }\n  async function playSong(){ if(!ac)buildAudioGraph(); if(ac.state===\"suspended\"){ try{await ac.resume();}catch(e){} }\n    const song=SONGS[curSong],base=SB+song.folder+\"/\",tok=++loadTok; setStatus(\"carregando \"+song.label+\"…\",\"#f4a02a\");\n    let bufs; try{ bufs=await Promise.all(song.stems.map(st=>loadBuf(base+st.f))); }catch(e){ setStatus(\"erro: \"+e.message,\"#e0483f\"); return; }\n    if(tok!==loadTok)return; stopSong(true); const t0=ac.currentTime+0.12;\n    song.stems.forEach((st,i)=>{ if(i>=24||!aNodes[i])return; const src=ac.createBufferSource(); src.buffer=bufs[i]; src.loop=true; src.connect(aNodes[i].trim); src.start(t0); realSources.push(src); });\n    for(let i=0;i<24;i++)applyChanAudio(i); playing=true; setPlayBtn(true); setStatus(\"tocando ♪ \"+song.label,\"#3ad07a\"); }\n  function stopSong(keep){ realSources.forEach(s=>{try{s.stop();}catch(e){}}); realSources=[]; playing=false; setPlayBtn(false); if(!keep)setStatus(\"parado\"); }\n\n  /* ================= LOOP / METERS ================= */\n  function loop(){ const now=perf(); processGates();\n    // bay meters\n    for(let i=0;i<bayStrips.length;i++){ const o=bayStrips[i]; if(!o.ctl){continue;} let db=o.ctl.meter?o.ctl.meter():-90; let t;\n      if(playing){ t=clamp((db+48)/48,0,1); if(o.ctl.kind!==''ch''&&o.ctl.kind!==''st''&&o.ctl.kind!==''mono'')t=0; }\n      else { if(o.ctl.kind===''ch''&&o.ctl.hasAudio()){ const c=CH_fromCtl(o.ctl); const env=0.5+0.5*Math.sin(now/(260+(c?c.i*23:0))+(c?c.i:0)); let post=(c?c.src+c.gain:-60)+(o.ctl.on?(o.ctl.fdb<=FMIN?-90:o.ctl.fdb):-90)+env*8-4; t=clamp((post+50)/50,0,1); } else t=0; }\n      o.meter.style.height=(t*100)+\"%\"; }\n    if(playing||state.mode!==\"overview\") drawScreen();\n    drawBridge();\n    requestAnimationFrame(loop);\n  }\n  function CH_fromCtl(ctl){ // find channel index by name match (ch only)\n    for(let i=0;i<24;i++) if(CH[i].name===ctl.name) return CH[i]; return null; }\n\n  /* ================= INIT ================= */\n  buildEqBands(); wireSelectedKnobs(); buildRightRack();\n  (function initAudioUI(){ const sel=$(\"#songSel\"); if(sel){ SONGS.forEach((s,i)=>{ const o=document.createElement(\"option\"); o.value=i; o.textContent=s.label; sel.appendChild(o); }); sel.value=0; sel.onchange=()=>{ const w=playing; stopSong(true); loadSong(+sel.value); if(w)playSong(); }; }\n    const pb=$(\"#playBtn\"); if(pb){ pb.onclick=()=>{ if(playing)stopSong(); else playSong(); }; } })();\n  buildBay(); loadSong(0); try{ buildAudioGraph(); }catch(e){}\n  updateSofUi(); paintMission(); paintRightRack();\n  window.addEventListener(\"resize\",sizeCanvas); setTimeout(sizeCanvas,30); requestAnimationFrame(loop);\n  setInterval(()=>{ const l=$(\"#danteLed\"); if(l){ l.classList.toggle(\"warn\"); setTimeout(()=>l.classList.remove(\"warn\"),120); } },4000);\n\n  /* ================= FIT (preserved) ================= */\n  function fitConsole(){ const con=document.querySelector(''.console''); if(!con)return;\n    const vw=window.innerWidth,vh=window.innerHeight;\n    if(vw<560){ document.body.classList.add(''stacked''); con.classList.add(''stacked''); con.style.zoom=''''; document.body.style.alignItems=''flex-start''; }\n    else{ document.body.classList.remove(''stacked''); con.classList.remove(''stacked''); con.style.zoom=''''; const _DW=con.offsetWidth, _DH=con.offsetHeight;\n      con.style.zoom=''''; const DW=con.offsetWidth||1520, DH=con.offsetHeight||940;   // mede o tamanho REAL\n      const scrH=(window.screen&&screen.height)||vh; const iframeTaller=vh>scrH+8; const visH=Math.min(vh,scrH);\n      const headerAllow=iframeTaller?84:(vh>700?40:6); const effVh=Math.max(240,visH-headerAllow);\n      document.body.style.alignItems=(iframeTaller||vh>700)?''flex-start'':''center'';\n      let s=Math.min((vw-16)/DW,effVh/DH); s=Math.max(0.3,Math.min(s,2.4)); con.style.zoom=s; }\n    try{ sizeCanvas(); }catch(e){}\n  }\n  window.addEventListener(''resize'',fitConsole); setTimeout(fitConsole,45);\n})();\n</script>\n</body>\n</html>\n"}]'::jsonb, updated_at = now() where lesson_id = '5504c000-5011-4a00-9000-0000000000b3' and tipo = 'interactive';

-- DiGiCo Quantum 338  <-  simuladores/som/digico-sd-real.html  (105.7 KB)
update public.ai_animations set urls = '[{"html":"<!doctype html>\n<html lang=\"pt-BR\">\n<head>\n<meta charset=\"utf-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1, maximum-scale=1, user-scalable=no\">\n<title>DiGiCo Quantum 338 — Simulador fiel (SMU)</title>\n<style>\n  :root{\n    --ink:#e7ecf5; --muted:#93a3ba; --amber:#22a8c0; --green:#3ad07a; --red:#e0483f; --cyan:#39c0e6;\n    --brand:#e2231a; /* DiGiCo logo red */\n    /* screen (touchscreen) DiGiCo charcoal palette */\n    --scr:#15181d;\n  }\n  *{box-sizing:border-box}\n  html,body{margin:0;height:100%}\n  body{\n    background:radial-gradient(1200px 700px at 50% -10%,#1a1d22,#0a0b0d 60%),#08090b;\n    color:var(--ink);\n    font-family:\"Inter\",system-ui,-apple-system,\"Segoe UI\",Roboto,sans-serif;\n    -webkit-font-smoothing:antialiased; user-select:none; overflow:hidden;\n    display:flex; align-items:flex-start; justify-content:center;\n  }\n  /* ===== CONSOLE: fixed design, scaled to fit ===== */\n  .console{position:relative;width:1520px;height:940px;flex:0 0 auto;transform-origin:top center;\n    display:flex;flex-direction:column;gap:8px;padding:12px;\n    background:\n      linear-gradient(180deg,#2a2c30,#1c1e21 8%,#161719 60%,#111214);\n    border:1px solid #050506;border-radius:16px;\n    box-shadow:0 30px 80px #000a, inset 0 1px 0 #ffffff10, inset 0 -2px 0 #0008;}\n  .console::before{content:\"\";position:absolute;inset:0;border-radius:16px;pointer-events:none;\n    background:linear-gradient(180deg,#ffffff08,transparent 6%);}\n\n  /* utility/top bar (play + song + missions) */\n  .util{display:flex;align-items:center;gap:8px;flex-wrap:wrap;\n    background:linear-gradient(180deg,#202329,#15171b);border:1px solid #0c0d0f;border-radius:10px;padding:6px 10px}\n  .util .brand{display:flex;align-items:center;gap:9px;margin-right:4px}\n  .util .brand b{font-size:17px;letter-spacing:1px;color:#eef2f8}\n  .util .brand .m{font-size:10px;letter-spacing:2px;color:#8a94a4;text-transform:uppercase}\n  .util .brand .y{color:var(--brand);font-weight:900;letter-spacing:0px}\n  /* DiGiCo Quantum logo plate */\n  .util .brand .dgclogo{background:linear-gradient(180deg,#101418,#05070a);border:1px solid #2a5560;color:#eef4f6;\n    font-weight:800;font-size:13px;letter-spacing:.3px;padding:4px 10px;border-radius:5px;white-space:nowrap;\n    box-shadow:0 1px 3px #000a, inset 0 1px 0 #ffffff12}\n  .util .brand .dgclogo b{color:var(--amber);font-size:13px;font-weight:800}\n  .util .brand .model{font-size:15px;font-weight:800;color:#eef2f8;letter-spacing:1.5px}\n  .pill{font-size:10.5px;color:var(--muted);background:#0c0e12;border:1px solid #2a2f37;border-radius:16px;padding:4px 9px;display:flex;align-items:center;gap:6px;letter-spacing:.4px}\n  .dot{width:8px;height:8px;border-radius:50%;background:var(--green);box-shadow:0 0 8px var(--green)}\n  .dot.warn{background:var(--amber);box-shadow:0 0 8px var(--amber)}\n  .btnp{font:inherit;font-size:11.5px;font-weight:700;border:0;border-radius:8px;padding:7px 12px;cursor:pointer}\n  .spacer{flex:1}\n  select.pill{cursor:pointer;color:var(--ink);font:inherit;font-size:11px;max-width:210px}\n  .mission{display:flex;align-items:center;gap:9px;background:#0c0e12;border:1px solid #2a2f37;border-radius:9px;padding:5px 10px;flex:1 1 320px;min-width:0}\n  .mission .idx{font-size:10px;color:var(--amber);font-weight:800;letter-spacing:1px;white-space:nowrap}\n  .mission .txt{font-size:11px;line-height:1.25;min-width:0}\n  .mission .txt small{color:var(--muted)}\n  .mission .txt b{color:#fff}\n  .ghost{background:transparent;color:var(--muted);border:1px solid #2a2f37}\n\n  /* meter bridge */\n  .bridge{background:linear-gradient(180deg,#101216,#0a0b0d);border:1px solid #0b0c0e;border-radius:10px;padding:6px 10px 4px;\n    box-shadow:inset 0 2px 6px #000a}\n  #mbridge{display:block;width:100%;height:58px}\n\n  /* ===== BACK (angled) SECTION: selected-channel | screen | right rack ===== */\n  .back{display:grid;grid-template-columns:342px 1fr 300px;gap:10px;min-height:0}\n  .panel{background:linear-gradient(180deg,#2b2e34,#212429 30%,#191b1f);border:1px solid #0c0d0f;border-radius:12px;\n    box-shadow:inset 0 1px 0 #ffffff0c, inset 0 -2px 4px #0006, 0 4px 12px #0006;padding:10px}\n  .sect-title{font-size:9px;letter-spacing:2px;color:#8b95a4;text-transform:uppercase;font-weight:700;margin:0 0 7px}\n  .sect-title b{color:var(--amber)}\n\n  /* Selected Channel physical knobs */\n  .selhead{display:flex;align-items:center;gap:8px;margin-bottom:8px}\n  .selhead .cc{width:9px;height:30px;border-radius:3px;background:var(--amber);box-shadow:0 0 6px #0006}\n  .selhead .nm{font-size:15px;font-weight:800;line-height:1.05;color:#f0f4fa}\n  .selhead .nn{font-size:9.5px;color:var(--muted);letter-spacing:.6px}\n  .knobrow{display:flex;gap:6px;align-items:flex-end;flex-wrap:wrap}\n  .kwrap{display:flex;flex-direction:column;align-items:center;gap:3px;width:52px}\n  .klbl{font-size:8px;letter-spacing:.4px;color:#93a0b2;text-transform:uppercase;text-align:center;line-height:1.05}\n  .kval{font-size:9.5px;font-weight:700;color:#e9eef6}\n  /* physical knob with LED collar */\n  .pk{--sz:36px;width:var(--sz);height:var(--sz);position:relative;touch-action:none;cursor:ns-resize}\n  .pk .ring{position:absolute;inset:-4px;border-radius:50%;\n    background:conic-gradient(from 215deg, var(--led,#6cf) calc(var(--p,0)*270deg), #0d0f13 0 270deg, #17191e 0);\n    -webkit-mask:radial-gradient(farthest-side,#0000 calc(100% - 4.5px),#000 calc(100% - 4px));\n            mask:radial-gradient(farthest-side,#0000 calc(100% - 4.5px),#000 calc(100% - 4px))}\n  .pk .cap{position:absolute;inset:2px;border-radius:50%;\n    background:radial-gradient(circle at 50% 32%,#565b64,#2b2e34 62%,#202329);\n    border:1px solid #121317;box-shadow:inset 0 2px 4px #0009, 0 1px 1px #ffffff10}\n  .pk .cap::after{content:\"\";position:absolute;left:50%;top:50%;width:3px;height:3px;border-radius:2px;background:#eef2f8;\n    box-shadow:0 0 3px #fff8;transform:translate(-50%,-50%) rotate(var(--rot,0deg)) translateY(calc(var(--sz)*-0.30))}\n  .pk.sm{--sz:30px}\n  /* small square panel buttons */\n  .pbtn{font:inherit;font-size:8.5px;font-weight:700;letter-spacing:.4px;color:#b9c6d8;text-align:center;cursor:pointer;\n    background:linear-gradient(180deg,#3a3f47,#23262c);border:1px solid #12141a;border-radius:5px;padding:5px 3px;\n    box-shadow:inset 0 1px 0 #ffffff12, 0 1px 2px #0007;min-width:0}\n  .pbtn:active{transform:translateY(1px)}\n  .pbtn.lit{color:#0b0f14;background:linear-gradient(180deg,#63d6e8,#22a8c0);border-color:#0b5561;box-shadow:0 0 8px #22a8c088}\n  .pbtn.green.lit{background:linear-gradient(180deg,#7ff0ac,#22b866);border-color:#0c5e33;box-shadow:0 0 8px #22b86688}\n  .pbtn.red.lit{background:linear-gradient(180deg,#ff9a92,#e0483f);border-color:#7a1611;box-shadow:0 0 8px #e0483f88}\n  .pbtn.nav{border-color:#2a3550}\n  .pbtn.nav.on{color:#0b0f14;background:linear-gradient(180deg,#8fd8ff,#39a8e6);border-color:#0d4d70;box-shadow:0 0 8px #39c0e688}\n  .brow{display:flex;gap:4px}\n  .eqbands{display:flex;gap:4px;margin-top:8px}\n  .eqband{flex:1;background:#191b20;border:1px solid #0c0d10;border-radius:7px;padding:5px 3px;display:flex;flex-direction:column;align-items:center;gap:4px}\n  .eqband .bt{font-size:8px;font-weight:800;letter-spacing:.5px;padding:2px 0;width:100%;text-align:center;border-radius:3px;color:#0b0f14}\n\n  /* SCREEN column */\n  .screencol{display:flex;flex-direction:column;min-height:0;padding:8px}\n  .tabs{display:flex;gap:4px;margin-bottom:7px;flex-wrap:wrap}\n  .tab{font:inherit;font-size:10px;font-weight:600;letter-spacing:.3px;color:#a9b6c8;cursor:pointer;\n    background:linear-gradient(180deg,#2f3views,#22252b);background:linear-gradient(180deg,#2f333b,#22252b);\n    border:1px solid #12141a;border-radius:6px;padding:5px 9px;box-shadow:inset 0 1px 0 #ffffff10}\n  .tab.active{color:#0b0f14;background:linear-gradient(180deg,#63d6e8,#22a8c0);border-color:#0b5561;font-weight:800}\n  .tab.sof{margin-left:auto}\n  .tab.sof.active{background:linear-gradient(180deg,#8fd8ff,#39a8e6);border-color:#0d4d70;color:#04121a}\n  .screen-bezel{flex:1;min-height:0;border-radius:10px;padding:8px;background:linear-gradient(180deg,#101216,#050607);\n    border:1px solid #000;box-shadow:inset 0 3px 12px #000c, 0 0 0 2px #2a2d33}\n  #screen{display:block;width:100%;height:100%;border-radius:6px;background:var(--scr);touch-action:none}\n\n  /* RIGHT RACK: user knobs / scene / user keys / monitor */\n  .rack{display:flex;flex-direction:column;gap:8px;min-height:0}\n  .rk{background:linear-gradient(180deg,#2b2e34,#1e2126);border:1px solid #0c0d0f;border-radius:10px;padding:8px 9px;\n    box-shadow:inset 0 1px 0 #ffffff0c,0 3px 8px #0005}\n  .udk{display:flex;justify-content:space-between;gap:6px}\n  .udk .kwrap{width:auto;flex:1}\n  .scene{display:flex;gap:9px;align-items:center}\n  .scenum{background:#07130c;border:1px solid #1c3a26;border-radius:7px;padding:5px 10px;min-width:96px;text-align:center;\n    box-shadow:inset 0 2px 6px #000}\n  .scenum .n{font-family:\"DS-Digital\",\"Courier New\",monospace;font-size:26px;font-weight:800;color:#37e08a;letter-spacing:2px;line-height:1;text-shadow:0 0 8px #37e08a66}\n  .scenum .l{font-size:8px;color:#5f8a72;letter-spacing:1px}\n  .scbtns{display:grid;grid-template-columns:1fr 1fr;gap:5px;flex:1}\n  .ukeys{display:grid;grid-template-columns:repeat(4,1fr);gap:5px}\n  .ukey{font:inherit;font-size:8px;font-weight:700;color:#cdd8e6;text-align:center;cursor:pointer;line-height:1.1;\n    background:linear-gradient(180deg,#3a3f47,#23262c);border:1px solid #12141a;border-radius:6px;padding:8px 2px;\n    box-shadow:inset 0 1px 0 #ffffff12,0 1px 2px #0007;min-height:34px;display:flex;align-items:center;justify-content:center}\n  .ukey .num{position:absolute}\n  .ukey.on{color:#0b0f14;background:linear-gradient(180deg,#8fd8ff,#39a8e6);border-color:#0d4d70;box-shadow:0 0 7px #39c0e666}\n  .monrow{display:flex;align-items:center;gap:10px}\n\n  /* ===== FRONT SECTION: fader bay ===== */\n  .front{background:linear-gradient(180deg,#232629,#191b1f);border:1px solid #0c0d0f;border-radius:12px;padding:8px;\n    box-shadow:inset 0 1px 0 #ffffff0a, 0 6px 16px #0006}\n  .bay{display:flex;gap:6px;align-items:stretch}\n  .block{display:flex;flex-direction:column;gap:5px;min-width:0}\n  .block .bhead{display:flex;gap:4px;align-items:center;flex-wrap:wrap;min-height:20px}\n  .block .btitle{font-size:8.5px;letter-spacing:1.2px;color:#8b95a4;text-transform:uppercase;font-weight:700;margin-right:2px}\n  .bkey{font:inherit;font-size:8px;font-weight:700;color:#b9c6d8;cursor:pointer;\n    background:linear-gradient(180deg,#33373f,#212429);border:1px solid #12141a;border-radius:5px;padding:3px 6px}\n  .bkey.on{color:#0b0f14;background:linear-gradient(180deg,#63d6e8,#22a8c0);border-color:#0b5561}\n  .strips{display:flex;gap:4px;flex:1}\n  .vsep{width:2px;align-self:stretch;background:linear-gradient(180deg,#0a0b0d,#33373f,#0a0b0d);border-radius:2px;margin:0 3px}\n\n  .strip{width:42px;flex:0 0 auto;background:linear-gradient(180deg,#1b1d22,#141519);border:1px solid #0b0c0e;border-radius:7px;\n    padding:4px 3px;display:flex;flex-direction:column;align-items:center;gap:4px;box-shadow:inset 0 1px 0 #ffffff08}\n  .strip.sel{border-color:var(--amber);box-shadow:0 0 0 1px var(--amber) inset,0 0 8px #22a8c044}\n  .strip .knob-s{margin-top:1px}\n  /* DiGiCo signature: tall per-channel TFT display above each fader */\n  .lcd{width:100%;height:40px;border-radius:5px;position:relative;overflow:hidden;border:1px solid #000;\n    box-shadow:inset 0 2px 5px #0009, 0 1px 0 #ffffff10;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:1px}\n  .lcd::after{content:\"\";position:absolute;left:0;right:0;top:0;height:46%;background:linear-gradient(180deg,#ffffff38,#ffffff00);pointer-events:none}\n  .lcd .cn{font-size:9px;font-weight:800;line-height:1.05;color:#0b0f14;text-align:center;padding:0 3px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;max-width:100%;position:relative;z-index:1}\n  .lcd .cnum{font-size:7px;font-weight:800;color:#0b0f14bb;line-height:1;letter-spacing:.5px;position:relative;z-index:1}\n  .sbtn{width:100%;font:inherit;font-size:8px;font-weight:800;letter-spacing:.3px;color:#93a0b2;cursor:pointer;text-align:center;\n    background:linear-gradient(180deg,#2b2f37,#1c1f25);border:1px solid #0b0c0e;border-radius:4px;padding:3px 0}\n  .row2{display:flex;gap:3px;width:100%}\n  .sbtn.sel.act{color:#0b0f14;background:linear-gradient(180deg,#63d6e8,#22a8c0);border-color:#0b5561}\n  .sbtn.cue.act{color:#0b0f14;background:linear-gradient(180deg,#8fd8ff,#39a8e6);border-color:#0d4d70}\n  .sbtn.on.act{color:#0b0f14;background:linear-gradient(180deg,#7ff0ac,#22b866);border-color:#0c5e33}\n  .fzone{display:flex;gap:4px;flex:1;width:100%;justify-content:center;min-height:150px}\n  .meter{width:6px;border-radius:2px;background:#05070a;position:relative;overflow:hidden;border:1px solid #14171d}\n  .meter i{position:absolute;left:0;right:0;bottom:0;height:0;background:linear-gradient(0deg,#37c86a,#37c86a 62%,#e8c33a 84%,#e0483f);transition:height .05s linear}\n  .fader{width:22px;flex:0 0 auto;position:relative;background:linear-gradient(90deg,#0a0b0d,#141519,#0a0b0d);border-radius:4px;border:1px solid #0b0c0e;cursor:ns-resize;touch-action:none}\n  .fader .trk{position:absolute;left:50%;top:8px;bottom:8px;width:2px;transform:translateX(-50%);background:#000}\n  .fader .u{position:absolute;left:2px;right:2px;height:1px;background:#39414f}\n  .cap{position:absolute;left:-4px;right:-4px;height:20px;border-radius:3px;cursor:grab;\n    background:linear-gradient(180deg,#20232a,#0e0f12 48%,#050506 52%,#16181d);border:1px solid #000;box-shadow:0 2px 4px #000a,inset 0 1px 0 #ffffff14}\n  .cap::after{content:\"\";position:absolute;left:3px;right:3px;top:50%;height:2px;transform:translateY(-50%);background:#c9d2e0;border-radius:1px}\n  .db{font-size:8px;font-weight:700;color:#c9d2e0;letter-spacing:.2px}\n  .db small{color:#7f8b9c;font-weight:600}\n  .strip.master .lcd{background:#2a1e06}\n  .strip.master .lcd .cn{color:#63d6e8}\n\n  .toast{position:fixed;left:50%;bottom:16px;transform:translateX(-50%) translateY(20px);\n    background:#12151a;border:1px solid var(--amber);color:var(--ink);padding:10px 16px;border-radius:10px;\n    font-size:12.5px;opacity:0;transition:.25s;pointer-events:none;z-index:50;box-shadow:0 8px 30px #000a}\n  .toast.show{opacity:1;transform:translateX(-50%) translateY(0)}\n  .toast b{color:var(--amber)}\n  .console:not(.stacked){touch-action:none}\n  body:not(.stacked){touch-action:none}\n  /* stacked (phone) */\n  .console.stacked{width:auto;max-width:700px;height:auto;transform:none!important;touch-action:auto}\n  .console.stacked .back{grid-template-columns:1fr}\n  .console.stacked .strip{width:38px}\n  body.stacked{overflow:auto}\n</style>\n</head>\n<body>\n<div class=\"console\" id=\"console\">\n\n  <!-- UTILITY BAR (play + song + missions) -->\n  <div class=\"util\">\n    <div class=\"brand\"><span class=\"dgclogo\">Di<b>Gi</b>Co</span><span class=\"model\">Quantum 338</span><span class=\"m\">Digital Mixing System · Simulador SMU</span></div>\n    <div class=\"pill\"><span class=\"dot\" id=\"danteLed\"></span> OPTOCORE <span id=\"danteTxt\" style=\"color:var(--ink)\">LOOP</span></div>\n    <div class=\"pill\">96 kHz</div>\n    <button class=\"btnp\" id=\"playBtn\" style=\"background:#22b866;color:#04121a\">► Tocar base</button>\n    <select id=\"songSel\" class=\"pill\"></select>\n    <span class=\"pill\" id=\"audioStatus\" style=\"color:var(--muted)\">áudio: —</span>\n    <div class=\"spacer\"></div>\n    <div class=\"mission\">\n      <span class=\"idx\" id=\"mIdx\">MISSÃO 1/5</span>\n      <span class=\"txt\" id=\"mTxt\">—</span>\n      <button class=\"btnp ghost\" id=\"mSkip\">Pular</button>\n    </div>\n  </div>\n\n  <!-- METER BRIDGE -->\n  <div class=\"bridge\"><canvas id=\"mbridge\"></canvas></div>\n\n  <!-- BACK SECTION -->\n  <div class=\"back\">\n\n    <!-- SELECTED CHANNEL (physical knobs) -->\n    <div class=\"panel\" id=\"selpanel\">\n      <div class=\"sect-title\"><b>CHANNEL STRIP</b> · CANAL SELECIONADO</div>\n      <div class=\"selhead\">\n        <div class=\"cc\" id=\"scCC\"></div>\n        <div><div class=\"nm\" id=\"scNM\">—</div><div class=\"nn\" id=\"scNN\">CH</div></div>\n        <div class=\"spacer\"></div>\n        <div class=\"brow\">\n          <button class=\"pbtn\" id=\"scPhase\" style=\"width:34px\">Φ</button>\n          <button class=\"pbtn\" id=\"scPhantom\" style=\"width:40px\">+48V</button>\n        </div>\n      </div>\n      <!-- HA / HPF / DYN row -->\n      <div class=\"knobrow\" style=\"margin-bottom:2px\">\n        <div class=\"kwrap\"><div class=\"pk\" data-k=\"gain\"><div class=\"ring\" style=\"--led:#5ecdd9\"></div><div class=\"cap\"></div></div><div class=\"klbl\">GAIN</div><div class=\"kval\" id=\"scGain\">+0</div></div>\n        <div class=\"kwrap\"><div class=\"pk\" data-k=\"hpf\"><div class=\"ring\" style=\"--led:#5ecdd9\"></div><div class=\"cap\"></div></div><div class=\"klbl\">HPF</div><div class=\"kval\" id=\"scHpf\">80</div></div>\n        <div class=\"kwrap\"><div class=\"pk\" data-k=\"gate\"><div class=\"ring\" style=\"--led:#6ce0a0\"></div><div class=\"cap\"></div></div><div class=\"klbl\">DYN1 THR</div><div class=\"kval\" id=\"scGate\">-40</div></div>\n        <div class=\"kwrap\"><div class=\"pk\" data-k=\"comp\"><div class=\"ring\" style=\"--led:#6cd0e6\"></div><div class=\"cap\"></div></div><div class=\"klbl\">DYN2 THR</div><div class=\"kval\" id=\"scComp\">-12</div></div>\n        <div class=\"kwrap\"><div class=\"pk\" data-k=\"pan\"><div class=\"ring\" style=\"--led:#cfd6e2\"></div><div class=\"cap\"></div></div><div class=\"klbl\">PAN</div><div class=\"kval\" id=\"scPan\">C</div></div>\n      </div>\n      <!-- access buttons (navigation) -->\n      <div class=\"brow\" style=\"margin:8px 0\">\n        <button class=\"pbtn nav\" data-nav=\"selected\" style=\"flex:1\">INPUT</button>\n        <button class=\"pbtn nav\" data-nav=\"eq\" style=\"flex:1\">EQ</button>\n        <button class=\"pbtn nav\" data-nav=\"gate\" style=\"flex:1\">DYN 1</button>\n        <button class=\"pbtn nav\" data-nav=\"comp\" style=\"flex:1\">DYN 2</button>\n      </div>\n      <!-- EQ 4-band physical knobs (Q / FREQ / GAIN per band) -->\n      <div class=\"sect-title\" style=\"margin:2px 0 4px\">EQUALIZER · 4 BAND</div>\n      <div class=\"eqbands\" id=\"eqbands\"></div>\n    </div>\n\n    <!-- SCREEN -->\n    <div class=\"panel screencol\">\n      <div class=\"tabs\" id=\"tabs\">\n        <button class=\"tab active\" data-mode=\"selected\">CHANNEL</button>\n        <button class=\"tab\" data-mode=\"overview\">OVERVIEW</button>\n        <button class=\"tab\" data-mode=\"eq\">EQ</button>\n        <button class=\"tab\" data-mode=\"gate\">DYN1</button>\n        <button class=\"tab\" data-mode=\"comp\">DYN2</button>\n        <button class=\"tab\" data-mode=\"sends\">SENDS</button>\n        <button class=\"tab\" data-mode=\"dca\">GRUPOS</button>\n        <button class=\"tab\" data-mode=\"fx\">FX RACK</button>\n        <button class=\"tab\" data-mode=\"scenes\">SNAPSHOTS</button>\n        <button class=\"tab\" data-mode=\"meter\">METER</button>\n        <button class=\"tab sof\" id=\"sofBtn\">AUX ▸ FADERS</button>\n      </div>\n      <div class=\"screen-bezel\"><canvas id=\"screen\"></canvas></div>\n    </div>\n\n    <!-- RIGHT RACK -->\n    <div class=\"rack\">\n      <div class=\"rk\">\n        <div class=\"sect-title\">ENCODERS ATRIBUIVEIS</div>\n        <div class=\"udk\" id=\"udknobs\"></div>\n      </div>\n      <div class=\"rk\">\n        <div class=\"sect-title\">SNAPSHOTS</div>\n        <div class=\"scene\">\n          <div class=\"scenum\"><div class=\"n\" id=\"scnNum\">001</div><div class=\"l\" id=\"scnName\">— SCENE —</div></div>\n          <div class=\"scbtns\">\n            <button class=\"pbtn\" id=\"scStore\">STORE</button>\n            <button class=\"pbtn green\" id=\"scRecall\">RECALL</button>\n            <button class=\"pbtn\" id=\"scInc\">INC ▲</button>\n            <button class=\"pbtn\" id=\"scDec\">DEC ▼</button>\n            <button class=\"pbtn\" id=\"scUndo\">UNDO</button>\n            <button class=\"pbtn\" id=\"scPrev\">PREVIEW</button>\n          </div>\n        </div>\n      </div>\n      <div class=\"rk\" style=\"flex:1;min-height:0\">\n        <div class=\"sect-title\">MACROS</div>\n        <div class=\"ukeys\" id=\"ukeys\"></div>\n      </div>\n      <div class=\"rk\">\n        <div class=\"sect-title\">MONITOR / TALKBACK</div>\n        <div class=\"monrow\">\n          <div class=\"kwrap\" style=\"width:46px\"><div class=\"pk sm\" data-k=\"monitor\"><div class=\"ring\" style=\"--led:#5ecdd9\"></div><div class=\"cap\"></div></div><div class=\"klbl\">MONITOR</div><div class=\"kval\" id=\"scMon\">-20</div></div>\n          <button class=\"pbtn red\" id=\"tbKey\" style=\"flex:1;min-height:40px\">TALKBACK</button>\n          <button class=\"pbtn nav\" id=\"dimKey\" style=\"flex:1;min-height:40px\">DIMMER</button>\n        </div>\n      </div>\n    </div>\n  </div>\n\n  <!-- FRONT SECTION: fader bay -->\n  <div class=\"front\">\n    <div class=\"bay\" id=\"bay\"></div>\n  </div>\n</div>\n<div class=\"toast\" id=\"toast\"></div>\n\n<script>\n\"use strict\";\n(function(){\n  /* ================= MODEL ================= */\n  const MIX_NAMES=[\"MIX 1 Mon\",\"MIX 2 Mon\",\"MIX 3 IEM\",\"MIX 4 IEM\",\"MIX 5 FX\",\"MIX 6 FX\",\"MIX 7 Sub\",\"MIX 8 FB\",\n    \"MIX 9\",\"MIX 10\",\"MIX 11\",\"MIX 12\",\"MIX 13\",\"MIX 14\",\"MIX 15\",\"MIX 16\",\"MIX 17\",\"MIX 18\",\"MIX 19\",\"MIX 20\",\"MIX 21\",\"MIX 22\",\"MIX 23\",\"MIX 24\"];\n  const N_MIX=24,N_MTX=8,N_DCA=16,N_MUTE=8,N_SCENE=10;\n  const COLORS=[\"#e0483f\",\"#f97316\",\"#22a8c0\",\"#eab308\",\"#3ad07a\",\"#14b8a6\",\"#39c0e6\",\"#3b82f6\",\"#6366f1\",\"#a855f7\",\"#ec4899\",\"#f43f5e\"];\n  const NAMES=[\"Kick In\",\"Snare\",\"Hat\",\"Tom 1\",\"Tom 2\",\"OH L\",\"OH R\",\"Bass DI\",\"Gtr L\",\"Gtr R\",\"Keys L\",\"Keys R\",\"Lead Voc\",\"Voc 2\",\"Voc 3\",\"Coro\",\"Sax\",\"Trumpet\",\"Perc\",\"Play L\",\"Play R\",\"Amb L\",\"Amb R\",\"Talk\"];\n  const RAWSRC=[-42,-40,-48,-44,-45,-47,-47,-38,-41,-41,-39,-39,-34,-40,-41,-43,-43,-44,-46,-36,-36,-52,-52,-30];\n  function mkChannel(i){\n    return { i, name:NAMES[i]||(\"CH \"+(i+1)), color:COLORS[i%COLORS.length],\n      gain:20+((i*7)%10)-4, phase:false, phantom:false, hpfOn:false, hpf:80, lpfOn:false, lpf:18000,\n      eq:[{type:''lowshelf'',f:120,g:0,q:0.7},{type:''peaking'',f:500,g:0,q:1.0},{type:''peaking'',f:2500,g:0,q:1.0},{type:''highshelf'',f:8000,g:0,q:0.7}],\n      eqType:''PRECISE'',\n      gateOn:false,gateThr:-40,gateRange:-60,gateAtk:1,gateHold:20,gateDecay:200,\n      compOn:false,compThr:-12,compRatio:3,compAtk:20,compRel:150,compKnee:2,compGain:0,\n      pan:0, fader:-4-((i*5)%8), on:true, cue:false,\n      sends:new Array(N_MIX).fill(-90), sendOn:new Array(N_MIX).fill(false), sendPre:new Array(N_MIX).fill(false),\n      dca:new Array(N_DCA).fill(false), mute:new Array(N_MUTE).fill(false),\n      fxRev:-90, fxDly:-90, src:RAWSRC[i]||-42 };\n  }\n  const CH=Array.from({length:24},(_,i)=>mkChannel(i));\n  const state={ sel:12, mode:\"selected\", sof:-1, sofBus:0, sofType:''mix'', master:-3, mono:-3, eqBand:3,\n    knobMode:''gain'', scene:0, monitor:-20, dim:false, talkback:false,\n    dcaGain:new Array(N_DCA).fill(0), dcaOn:new Array(N_DCA).fill(true),\n    mixMaster:new Array(N_MIX).fill(0), mixOn:new Array(N_MIX).fill(true),\n    mtxMaster:new Array(N_MTX).fill(0), mtxOn:new Array(N_MTX).fill(true),\n    muteActive:new Array(N_MUTE).fill(false),\n    fx:{revMix:0.35,revSize:2.2,dlyTime:0.38,dlyFb:0.35,dlyMix:0.3} };\n  const scenes=new Array(N_SCENE).fill(null);\n  const ukState={}; // user key toggles\n\n  /* ================= HELPERS ================= */\n  const $=s=>document.querySelector(s);\n  const clamp=(v,a,b)=>Math.max(a,Math.min(b,v));\n  const FMIN=-90,FMAX=10;\n  function faderTxt(db){ return db<=FMIN?\"−∞\":(db>0?\"+\":\"\")+db.toFixed(1); }\n  function panTxt(p){ if(Math.abs(p)<2)return\"C\"; return (p<0?\"L\"+Math.round(-p):\"R\"+Math.round(p)); }\n  function pos2db(p){ if(p<=0.01)return FMIN; return clamp(-60+p*70,FMIN,FMAX); }\n  function db2pos(db){ if(db<=FMIN)return 0; return clamp((db+60)/70,0,1); }\n  function fx(f){ const mn=Math.log10(20),mx=Math.log10(20000); return (Math.log10(f)-mn)/(mx-mn); }\n  function fInv(t){ const mn=Math.log10(20),mx=Math.log10(20000); return Math.pow(10,mn+clamp(t,0,1)*(mx-mn)); }\n  function perf(){ return performance.now(); }\n\n  /* ================= SCREEN COLOR THEME (DiGiCo charcoal touchscreen) ================= */\n  const SC={ bg0:\"#0f1114\",bg1:\"#181b1f\", panel:\"#23272d\", panelHi:\"#2b3037\", panelLo:\"#1a1d22\",\n    border:\"#3b424a\", line:\"#2c333b\", grid:\"#242a31\",\n    ink:\"#e8ecf1\", mut:\"#9aa6b3\", dim:\"#616c78\",\n    amber:\"#22a8c0\", green:\"#46c98a\", red:\"#e5424a\", cyan:\"#35b8c4\",\n    band:[\"#e0554e\",\"#e6b34e\",\"#5cc98a\",\"#4ea6e0\"] };\n\n  /* ================= biquad magnitude (matches Web Audio) ================= */\n  const FS=48000;\n  function biquadDb(type,f0,gainDb,Q,f){\n    f0=clamp(f0,10,FS/2-10);Q=Math.max(0.05,Q);\n    const w0=2*Math.PI*f0/FS,cw=Math.cos(w0),sw=Math.sin(w0),A=Math.pow(10,gainDb/40),alpha=sw/(2*Q);\n    let b0,b1,b2,a0,a1,a2;\n    if(type===''peaking''){b0=1+alpha*A;b1=-2*cw;b2=1-alpha*A;a0=1+alpha/A;a1=-2*cw;a2=1-alpha/A;}\n    else if(type===''lowshelf''){const s2=2*Math.sqrt(A)*alpha;b0=A*((A+1)-(A-1)*cw+s2);b1=2*A*((A-1)-(A+1)*cw);b2=A*((A+1)-(A-1)*cw-s2);a0=(A+1)+(A-1)*cw+s2;a1=-2*((A-1)+(A+1)*cw);a2=(A+1)+(A-1)*cw-s2;}\n    else if(type===''highshelf''){const s2=2*Math.sqrt(A)*alpha;b0=A*((A+1)+(A-1)*cw+s2);b1=-2*A*((A-1)+(A+1)*cw);b2=A*((A+1)+(A-1)*cw-s2);a0=(A+1)-(A-1)*cw+s2;a1=2*((A-1)-(A+1)*cw);a2=(A+1)-(A-1)*cw-s2;}\n    else if(type===''highpass''){b0=(1+cw)/2;b1=-(1+cw);b2=(1+cw)/2;a0=1+alpha;a1=-2*cw;a2=1-alpha;}\n    else {b0=(1-cw)/2;b1=1-cw;b2=(1-cw)/2;a0=1+alpha;a1=-2*cw;a2=1-alpha;}\n    const w=2*Math.PI*f/FS,phi=Math.pow(Math.sin(w/2),2);\n    const num=Math.pow(b0+b1+b2,2)-4*(b0*b1+4*b0*b2+b1*b2)*phi+16*b0*b2*phi*phi;\n    const den=Math.pow(a0+a1+a2,2)-4*(a0*a1+4*a0*a2+a1*a2)*phi+16*a0*a2*phi*phi;\n    return 10*Math.log10(Math.max(1e-9,num)/Math.max(1e-9,den));\n  }\n  function eqTypeFactor(t){ return t===''AGGRESSIVE''?1.55:t===''SMOOTH''?0.6:t===''LEGACY''?0.82:1; }\n  function eqMag(ch,f){ let g=0; const kf=eqTypeFactor(ch.eqType||''PRECISE'');\n    for(const b of ch.eq){ if(b.g!==0) g+=biquadDb(b.type,b.f,b.g,b.q*kf,f); }\n    if(ch.hpfOn) g+=biquadDb(''highpass'',ch.hpf,0,0.707,f);\n    if(ch.lpfOn) g+=biquadDb(''lowpass'',ch.lpf,0,0.707,f);\n    return clamp(g,-30,20); }\n\n  /* ================= SELECTED CHANNEL PHYSICAL KNOBS ================= */\n  const KDEF={ gain:{min:-6,max:45}, hpf:{min:20,max:600,log:true}, gate:{min:-72,max:0}, comp:{min:-54,max:0}, pan:{min:-63,max:63},\n    monitor:{min:-60,max:0}, eqQ:{min:0.1,max:10,log:true}, eqF:{min:20,max:20000,log:true}, eqG:{min:-18,max:18} };\n  function knobP(def,v){ if(def.log) return clamp((Math.log(Math.max(def.min,v))-Math.log(def.min))/(Math.log(def.max)-Math.log(def.min)),0,1); return clamp((v-def.min)/(def.max-def.min),0,1); }\n  function setPK(el,def,v){ const p=knobP(def,v); el.style.setProperty(''--p'',p); el.style.setProperty(''--rot'',(-135+p*270)+''deg''); }\n  function pkVal(ch,k){ return {gain:ch.gain,hpf:ch.hpf,gate:ch.gateThr,comp:ch.compThr,pan:ch.pan,monitor:state.monitor}[k]; }\n  function pkSet(ch,k,v){ const d=KDEF[k]; v=clamp(v,d.min,d.max);\n    if(k===''gain'')ch.gain=v; else if(k===''hpf'')ch.hpf=Math.round(v); else if(k===''gate'')ch.gateThr=Math.round(v);\n    else if(k===''comp'')ch.compThr=Math.round(v); else if(k===''pan'')ch.pan=Math.round(v);\n    else if(k===''monitor''){ state.monitor=Math.round(v); applyMonitor(); } }\n\n  // build EQ 4-band knob columns\n  function buildEqBands(){\n    const host=$(\"#eqbands\"); host.innerHTML=\"\";\n    const nm=[\"LOW\",\"LO-MID\",\"HI-MID\",\"HIGH\"];\n    for(let b=0;b<4;b++){\n      const col=document.createElement(\"div\"); col.className=\"eqband\";\n      col.innerHTML=`<div class=\"bt\" style=\"background:${SC.band[b]}\">${nm[b]}</div>\n        <div class=\"pk sm\" data-eq=\"${b}\" data-p=\"g\"><div class=\"ring\" style=\"--led:${SC.band[b]}\"></div><div class=\"cap\"></div></div><div class=\"klbl\">GAIN</div><div class=\"kval\" data-v=\"g${b}\">0.0</div>\n        <div class=\"pk sm\" data-eq=\"${b}\" data-p=\"f\"><div class=\"ring\" style=\"--led:${SC.band[b]}\"></div><div class=\"cap\"></div></div><div class=\"klbl\">FREQ</div><div class=\"kval\" data-v=\"f${b}\">1k</div>\n        <div class=\"pk sm\" data-eq=\"${b}\" data-p=\"q\"><div class=\"ring\" style=\"--led:${SC.band[b]}\"></div><div class=\"cap\"></div></div><div class=\"klbl\">Q</div><div class=\"kval\" data-v=\"q${b}\">1.0</div>`;\n      host.appendChild(col);\n    }\n  }\n  function fmtFreq(f){ return f>=1000?(f/1000).toFixed(f>=10000?0:1)+\"k\":Math.round(f); }\n  function wirePKDrag(el,getV,setV,def){\n    let drag=false,lastY=0;\n    el.addEventListener(\"pointerdown\",e=>{drag=true;lastY=e.clientY;el.setPointerCapture(e.pointerId);e.preventDefault();});\n    el.addEventListener(\"pointermove\",e=>{ if(!drag)return; const dy=lastY-e.clientY; lastY=e.clientY;\n      const span=def.log?1:(def.max-def.min); let v=getV();\n      if(def.log){ let p=knobP(def,v)+dy/180; p=clamp(p,0,1); v=def.min*Math.pow(def.max/def.min,p); }\n      else v=v+dy*span/180;\n      setV(clamp(v,def.min,def.max)); e.preventDefault(); });\n    const up=()=>drag=false; el.addEventListener(\"pointerup\",up); el.addEventListener(\"pointercancel\",up);\n  }\n  function wireSelectedKnobs(){\n    document.querySelectorAll(''.pk[data-k]'').forEach(el=>{ const k=el.dataset.k; const def=KDEF[k];\n      wirePKDrag(el, ()=>pkVal(CH[state.sel],k), v=>{ pkSet(CH[state.sel],k,v); if(k!==''monitor'')applyChanAudio(state.sel); paintSelected(); drawScreen(); checkMissions(); }, def);\n    });\n    document.querySelectorAll(''.pk[data-eq]'').forEach(el=>{ const b=+el.dataset.eq, p=el.dataset.p;\n      const def=p===''g''?KDEF.eqG:p===''f''?KDEF.eqF:KDEF.eqQ;\n      wirePKDrag(el, ()=>{ const bd=CH[state.sel].eq[b]; return p===''g''?bd.g:p===''f''?bd.f:bd.q; },\n        v=>{ const bd=CH[state.sel].eq[b]; if(p===''g'')bd.g=v; else if(p===''f'')bd.f=Math.round(v); else bd.q=v; state.eqBand=b; applyChanAudio(state.sel); paintSelected(); drawScreen(); checkMissions(); }, def);\n    });\n    // phase / phantom\n    $(\"#scPhase\").onclick=()=>{ const c=CH[state.sel]; c.phase=!c.phase; applyChanAudio(c.i); paintSelected(); toast(c.phase?\"Fase Ø <b>invertida</b>\":\"Fase normal\"); };\n    $(\"#scPhantom\").onclick=()=>{ const c=CH[state.sel]; c.phantom=!c.phantom; paintSelected(); toast(c.phantom?\"<b>+48V</b> phantom ON\":\"+48V OFF\"); };\n    // nav (access) buttons -> open screens\n    document.querySelectorAll(''.pbtn.nav[data-nav]'').forEach(el=>{ el.onclick=()=>setMode(el.dataset.nav); });\n  }\n  function paintSelected(){\n    const ch=CH[state.sel];\n    $(\"#scCC\").style.background=ch.color; $(\"#scNM\").textContent=ch.name; $(\"#scNN\").textContent=\"CH \"+(ch.i+1);\n    $(\"#scGain\").textContent=(ch.gain>0?\"+\":\"\")+ch.gain.toFixed(0);\n    $(\"#scHpf\").textContent=ch.hpf; $(\"#scGate\").textContent=ch.gateThr; $(\"#scComp\").textContent=ch.compThr; $(\"#scPan\").textContent=panTxt(ch.pan);\n    $(\"#scMon\").textContent=state.monitor;\n    setPK($(''.pk[data-k=\"gain\"]''),KDEF.gain,ch.gain); setPK($(''.pk[data-k=\"hpf\"]''),KDEF.hpf,ch.hpf);\n    setPK($(''.pk[data-k=\"gate\"]''),KDEF.gate,ch.gateThr); setPK($(''.pk[data-k=\"comp\"]''),KDEF.comp,ch.compThr);\n    setPK($(''.pk[data-k=\"pan\"]''),KDEF.pan,ch.pan); setPK($(''.pk[data-k=\"monitor\"]''),KDEF.monitor,state.monitor);\n    ch.eq.forEach((b,bi)=>{\n      setPK($(`.pk[data-eq=\"${bi}\"][data-p=\"g\"]`),KDEF.eqG,b.g);\n      setPK($(`.pk[data-eq=\"${bi}\"][data-p=\"f\"]`),KDEF.eqF,b.f);\n      setPK($(`.pk[data-eq=\"${bi}\"][data-p=\"q\"]`),KDEF.eqQ,b.q);\n      $(`[data-v=\"g${bi}\"]`).textContent=(b.g>0?\"+\":\"\")+b.g.toFixed(1);\n      $(`[data-v=\"f${bi}\"]`).textContent=fmtFreq(b.f);\n      $(`[data-v=\"q${bi}\"]`).textContent=b.q.toFixed(2);\n    });\n    $(\"#scPhase\").classList.toggle(\"lit\",ch.phase);\n    $(\"#scPhantom\").classList.toggle(\"red\",true); $(\"#scPhantom\").classList.toggle(\"lit\",ch.phantom);\n    // nav highlight\n    document.querySelectorAll(''.pbtn.nav[data-nav]'').forEach(el=>el.classList.toggle(\"on\",el.dataset.nav===state.mode));\n  }\n  function selectChannel(i){ state.sel=i; paintSelected(); paintBay(); drawScreen(); checkMissions(); }\n\n  /* ================= placeholder forward decls upgraded below ================= */\n  let paintBay=function(){}, renderScreen=function(){}, applyChanAudio=function(){}, applyMonitor=function(){};\n  // Redraw coalescing: many pointermove events during a fader/knob drag must NOT each\n  // trigger a full synchronous canvas repaint (that starves the main thread on iPad and\n  // makes faders lag and jump). drawScreen() just flags \"dirty\"; the rAF loop paints once/frame.\n  let _drawReq=0; function drawScreen(){ if(_drawReq)return; _drawReq=requestAnimationFrame(function(){ _drawReq=0; renderScreen(); }); }\n\n  /* ================= FADER BAY ================= */\n  const BAY=$(\"#bay\"); let bayStrips=[];\n  // block layer configuration\n  const leftBank={cur:0, banks:[ {t:''ch'',from:0,n:16,label:''CH 1-16''}, {t:''ch'',from:16,n:16,label:''CH 17-24''}, {t:''empty'',n:16,label:''CUSTOM''} ]};\n  const rightBank={cur:0, banks:[ {t:''ch'',from:16,n:8,label:''CH 17-24''}, {t:''ch'',from:0,n:8,label:''CH 1-8''}, {t:''ch'',from:8,n:8,label:''CH 9-16''} ]};\n  const centerLayer={cur:0, layers:[ {t:''dca'',from:0,label:''DCA 1-8''}, {t:''dca'',from:8,label:''DCA 9-16''}, {t:''mix'',from:0,label:''MIX 1-8''}, {t:''mix'',from:8,label:''MIX 9-16''}, {t:''mix'',from:16,label:''MIX 17-24''}, {t:''mtx'',from:0,label:''MATRIX''} ]};\n\n  function stripDesc(kind,idx){\n    // returns interface object per strip\n    if(kind===''ch''){\n      return { kind, get name(){return CH[idx].name;}, get color(){return CH[idx].color;}, get num(){return \"CH\"+(idx+1);},\n        get sel(){return state.sel===idx;}, doSel(){ selectChannel(idx); }, get chIdx(){return idx;},\n        get on(){ return state.sof>=0 ? CH[idx].sendOn[state.sofBus] : CH[idx].on; },\n        toggleOn(){ const c=CH[idx]; if(state.sof>=0){ c.sendOn[state.sofBus]=!c.sendOn[state.sofBus]; } else { c.on=!c.on; applyChanAudio(idx); } },\n        get fdb(){ return state.sof>=0 ? CH[idx].sends[state.sofBus] : CH[idx].fader; },\n        setFdb(v){ const c=CH[idx]; if(state.sof>=0){ c.sends[state.sofBus]=v; if(v>FMIN)c.sendOn[state.sofBus]=true; } else { c.fader=v; applyChanAudio(idx); } },\n        get knobVal(){ return state.knobMode===''pan''?CH[idx].pan:CH[idx].gain; },\n        setKnob(dy){ const c=CH[idx]; if(state.knobMode===''pan''){ c.pan=clamp(Math.round(c.pan+dy),-63,63);} else { c.gain=clamp(c.gain+dy*0.4,-6,45);} applyChanAudio(idx); },\n        meter(){ return meterDbOf(idx); }, sofActive(){return false;}, hasAudio(){return CH[idx].hasAudio;} };\n    }\n    if(kind===''dca''){\n      return { kind, get name(){return \"DCA \"+(idx+1);}, get color(){return \"#22a8c0\";}, get num(){return \"DCA\";},\n        get sel(){return false;}, doSel(){ setMode(''dca''); },\n        get on(){ return state.dcaOn[idx]; }, toggleOn(){ state.dcaOn[idx]=!state.dcaOn[idx]; for(let i=0;i<24;i++)if(CH[i].dca[idx])applyChanAudio(i); },\n        get fdb(){ return state.dcaGain[idx]; }, setFdb(v){ state.dcaGain[idx]=v; for(let i=0;i<24;i++)if(CH[i].dca[idx])applyChanAudio(i); },\n        get knobVal(){return 0;}, setKnob(){}, meter(){return -90;}, sofActive(){return false;}, hasAudio(){return true;} };\n    }\n    if(kind===''mix''){\n      return { kind, get name(){return MIX_NAMES[idx];}, get color(){return \"#39c0e6\";}, get num(){return \"MIX\"+(idx+1);},\n        get sel(){ return state.sof>=0&&state.sofType===''mix''&&state.sofBus===idx; },\n        doSel(){ engageSof(''mix'',idx); },\n        get on(){ return state.mixOn[idx]; }, toggleOn(){ state.mixOn[idx]=!state.mixOn[idx]; },\n        get fdb(){ return state.mixMaster[idx]; }, setFdb(v){ state.mixMaster[idx]=v; },\n        get knobVal(){return 0;}, setKnob(){}, meter(){return -90;}, sofActive(){return true;}, hasAudio(){return true;} };\n    }\n    if(kind===''mtx''){\n      return { kind, get name(){return \"MATRIX \"+(idx+1);}, get color(){return \"#a855f7\";}, get num(){return \"MTX\"+(idx+1);},\n        get sel(){ return state.sof>=0&&state.sofType===''mtx''&&state.sofBus===idx; }, doSel(){ engageSof(''mtx'',idx); },\n        get on(){ return state.mtxOn[idx]; }, toggleOn(){ state.mtxOn[idx]=!state.mtxOn[idx]; },\n        get fdb(){ return state.mtxMaster[idx]; }, setFdb(v){ state.mtxMaster[idx]=v; },\n        get knobVal(){return 0;}, setKnob(){}, meter(){return -90;}, sofActive(){return true;}, hasAudio(){return true;} };\n    }\n    if(kind===''st''){\n      return { kind, get name(){return \"STEREO\";}, get color(){return \"#63d6e8\";}, get num(){return \"ST\";},\n        get sel(){return false;}, doSel(){}, get on(){return true;}, toggleOn(){},\n        get fdb(){return state.master;}, setFdb(v){ state.master=v; applyMasterAudio(); },\n        get knobVal(){return 0;}, setKnob(){}, meter(){return playing?masterLevelDb():-90;}, sofActive(){return false;}, hasAudio(){return true;} };\n    }\n    if(kind===''mono''){\n      return { kind, get name(){return \"MONO\";}, get color(){return \"#63d6e8\";}, get num(){return \"M/C\";},\n        get sel(){return false;}, doSel(){}, get on(){return true;}, toggleOn(){},\n        get fdb(){return state.mono;}, setFdb(v){ state.mono=v; applyMasterAudio(); },\n        get knobVal(){return 0;}, setKnob(){}, meter(){return playing?masterLevelDb()-2:-90;}, sofActive(){return false;}, hasAudio(){return true;} };\n    }\n    return { kind:''empty'', name:\"—\", color:\"#2a2f37\", num:\"\", sel:false, doSel(){}, on:false, toggleOn(){}, fdb:FMIN, setFdb(){}, knobVal:0, setKnob(){}, meter(){return -90;}, sofActive(){return false;}, hasAudio(){return false;} };\n  }\n  function meterDbOf(i){ const ch=CH[i];\n    if(playing&&ch.hasAudio) return chLevelDb(i)+(ch.on?0:-90);\n    if(!ch.hasAudio) return -90;\n    return ch.src+ch.gain+(ch.on?Math.min(0,ch.fader):-90); }\n\n  function currentDescriptors(){\n    const list=[]; // {block, ctl}\n    const lb=leftBank.banks[leftBank.cur];\n    for(let s=0;s<16;s++){ let d; if(lb.t===''empty'')d=stripDesc(''empty''); else { const gi=lb.from+s; d= gi<24?stripDesc(''ch'',gi):stripDesc(''empty''); } list.push({block:''L'',ctl:d}); }\n    const cl=centerLayer.layers[centerLayer.cur];\n    for(let s=0;s<8;s++){ list.push({block:''C'',ctl:stripDesc(cl.t, cl.from+s)}); }\n    const rb=rightBank.banks[rightBank.cur];\n    for(let s=0;s<8;s++){ const gi=rb.from+s; list.push({block:''R'',ctl: gi<24?stripDesc(''ch'',gi):stripDesc(''empty'')}); }\n    list.push({block:''M'',ctl:stripDesc(''st'')}); list.push({block:''M'',ctl:stripDesc(''mono'')});\n    return list;\n  }\n\n  function buildBay(){\n    BAY.innerHTML=\"\"; bayStrips=[];\n    const mkBlock=(title,keys,onKey,curIdx)=>{\n      const blk=document.createElement(\"div\"); blk.className=\"block\";\n      const head=document.createElement(\"div\"); head.className=\"bhead\";\n      const bt=document.createElement(\"span\"); bt.className=\"btitle\"; bt.textContent=title; head.appendChild(bt);\n      keys.forEach((k,ki)=>{ const b=document.createElement(\"button\"); b.className=\"bkey\"+(ki===curIdx?\" on\":\"\"); b.textContent=k;\n        b.onclick=()=>{ onKey(ki); }; head.appendChild(b); });\n      const strips=document.createElement(\"div\"); strips.className=\"strips\";\n      blk.appendChild(head); blk.appendChild(strips);\n      return {blk,strips,head};\n    };\n    // LEFT\n    const L=mkBlock(\"INPUT\", leftBank.banks.map(b=>b.label), i=>{ leftBank.cur=i; buildBay(); paintBay(); }, leftBank.cur);\n    BAY.appendChild(L.blk);\n    for(let s=0;s<16;s++) bayStrips.push(mkStrip(L.strips));\n    const sep1=document.createElement(\"div\"); sep1.className=\"vsep\"; BAY.appendChild(sep1);\n    // CENTER (Centralogic)\n    const C=mkBlock(\"GRUPOS\", centerLayer.layers.map(l=>l.label), i=>{ centerLayer.cur=i; buildBay(); paintBay(); }, centerLayer.cur);\n    BAY.appendChild(C.blk);\n    for(let s=0;s<8;s++) bayStrips.push(mkStrip(C.strips));\n    const sep2=document.createElement(\"div\"); sep2.className=\"vsep\"; BAY.appendChild(sep2);\n    // RIGHT\n    const R=mkBlock(\"INPUT\", rightBank.banks.map(b=>b.label), i=>{ rightBank.cur=i; buildBay(); paintBay(); }, rightBank.cur);\n    BAY.appendChild(R.blk);\n    for(let s=0;s<8;s++) bayStrips.push(mkStrip(R.strips));\n    const sep3=document.createElement(\"div\"); sep3.className=\"vsep\"; BAY.appendChild(sep3);\n    // MASTER\n    const M=mkBlock(\"MASTER\",[\"GAIN/PAN\"],()=>{ state.knobMode=state.knobMode===''gain''?''pan'':''gain''; paintBay(); toast(\"Knob = \"+(state.knobMode===''gain''?\"GAIN\":\"PAN\")); },-1);\n    BAY.appendChild(M.blk);\n    bayStrips.push(mkStrip(M.strips,true)); bayStrips.push(mkStrip(M.strips,true));\n  }\n  function mkStrip(host,master){\n    const st=document.createElement(\"div\"); st.className=\"strip\"+(master?\" master\":\"\");\n    st.innerHTML=`\n      <div class=\"pk sm knob-s\"><div class=\"ring\" style=\"--led:#5ecdd9\"></div><div class=\"cap\"></div></div>\n      <div class=\"lcd\"><div class=\"cn\"></div><div class=\"cnum\"></div></div>\n      <div class=\"row2\"><button class=\"sbtn sel\">SEL</button><button class=\"sbtn cue\">SOLO</button></div>\n      <div class=\"fzone\"><div class=\"meter\"><i></i></div><div class=\"fader\"><div class=\"trk\"></div><div class=\"u\"></div><div class=\"cap capf\"></div></div></div>\n      <button class=\"sbtn on\">ON</button>`;\n    host.appendChild(st);\n    const o={ root:st, knob:st.querySelector(\".knob-s\"), lcd:st.querySelector(\".lcd\"), cn:st.querySelector(\".cn\"), cnum:st.querySelector(\".cnum\"),\n      sel:st.querySelector(\".sbtn.sel\"), cue:st.querySelector(\".sbtn.cue\"), on:st.querySelector(\".sbtn.on\"),\n      meter:st.querySelector(\".meter i\"), fader:st.querySelector(\".fader\"), cap:st.querySelector(\".capf\"), ctl:null, cueOn:false };\n    wireStrip(o);\n    return o;\n  }\n  function wireStrip(o){\n    // fader\n    let drag=false;\n    const toDb=cy=>{ const r=o.fader.getBoundingClientRect(); return pos2db(1-(cy-r.top)/r.height); };\n    const mv=e=>{ if(!drag||!o.ctl)return; o.ctl.setFdb(toDb(e.clientY)); paintOneStrip(o); if(state.mode!==\"overview\")drawScreen(); checkMissions(); e.preventDefault(); };\n    o.fader.addEventListener(\"pointerdown\",e=>{ drag=true; o.fader.setPointerCapture(e.pointerId); mv(e); e.preventDefault(); });\n    o.fader.addEventListener(\"pointermove\",mv);\n    const up=()=>drag=false; o.fader.addEventListener(\"pointerup\",up); o.fader.addEventListener(\"pointercancel\",up);\n    // knob\n    let kd=false,ky=0;\n    o.knob.addEventListener(\"pointerdown\",e=>{kd=true;ky=e.clientY;o.knob.setPointerCapture(e.pointerId);e.preventDefault();});\n    o.knob.addEventListener(\"pointermove\",e=>{ if(!kd||!o.ctl)return; const dy=ky-e.clientY; ky=e.clientY; o.ctl.setKnob(dy); paintOneStrip(o); paintSelected(); e.preventDefault(); });\n    const kup=()=>kd=false; o.knob.addEventListener(\"pointerup\",kup); o.knob.addEventListener(\"pointercancel\",kup);\n    // keys\n    o.sel.onclick=()=>{ if(o.ctl){ o.ctl.doSel(); paintBay(); } };\n    o.cue.onclick=()=>{ const c=o.ctl; if(c&&c.kind===''ch''){ CH[c.chIdx].cue=!CH[c.chIdx].cue; applyCue(); } };\n    o.on.onclick=()=>{ if(o.ctl){ o.ctl.toggleOn(); paintBay(); if(state.mode!==\"overview\")drawScreen(); checkMissions(); } };\n  }\n  paintBay=function(){\n    const descs=currentDescriptors();\n    for(let i=0;i<bayStrips.length;i++){ const o=bayStrips[i], d=descs[i]; if(!d){continue;} o.ctl=d.ctl; paintOneStrip(o); }\n  };\n  // CUE = SOLO-in-place (AFL): se algum canal está em CUE, só os canais em CUE são ouvidos.\n  function anyCue(){ for(let i=0;i<CH.length;i++){ if(CH[i].cue) return true; } return false; }\n  function applyCue(){ for(let i=0;i<CH.length;i++) applyChanAudio(i); if(typeof paintBay===''function'') paintBay(); if(state.mode!==\"overview\") drawScreen(); }\n  function clearCue(){ for(let i=0;i<CH.length;i++) CH[i].cue=false; applyCue(); }\n  function paintOneStrip(o){\n    const c=o.ctl; if(!c){return;}\n    const empty=c.kind===''empty'';\n    o.cn.textContent=empty?\"\":c.name; o.cnum.textContent=empty?\"\":c.num;\n    o.lcd.style.background=empty?\"#15171b\":c.color;\n    o.cn.style.color = pickInk(c.color); o.cnum.style.color=pickInk(c.color)+\"aa\";\n    o.root.classList.toggle(\"sel\", !!c.sel);\n    const fdb=c.fdb; o.cap.style.bottom=\"calc(\"+(db2pos(fdb)*100)+\"% - 10px)\";\n    o.sel.classList.toggle(\"act\", !!c.sel);\n    o.on.classList.toggle(\"act\", !!c.on);\n    o.cue.classList.toggle(\"act\", c.kind===''ch'' && CH[c.chIdx] && !!CH[c.chIdx].cue);\n    o.on.textContent = (state.sof>=0&&c.kind===''ch'')? (c.on?\"SEND\":\"OFF\") : \"ON\";\n    o.knob.style.visibility = (c.kind===''ch'')?''visible'':''hidden'';\n    if(c.kind===''ch''){ setPK(o.knob, state.knobMode===''pan''?KDEF.pan:KDEF.gain, c.knobVal); }\n    o.fader.style.opacity = empty?0.35:1;\n  }\n  function pickInk(hex){ // black or white text on channel color\n    const h=hex.replace(''#'',''''); if(h.length<6)return \"#0b0f14\";\n    const r=parseInt(h.substr(0,2),16),g=parseInt(h.substr(2,2),16),b=parseInt(h.substr(4,2),16);\n    return (0.299*r+0.587*g+0.114*b)>150?\"#0b0f14\":\"#f4f8ff\"; }\n\n  function engageSof(type,bus){\n    if(state.sof>=0 && state.sofType===type && state.sofBus===bus){ state.sof=-1; }\n    else { state.sof=0; state.sofType=type; state.sofBus=bus; }\n    updateSofUi(); paintBay(); drawScreen();\n  }\n  function updateSofUi(){\n    const on=state.sof>=0; const btn=$(\"#sofBtn\");\n    btn.classList.toggle(\"active\",on);\n    btn.textContent = on ? (\"AUX ▸ FADERS: \"+(state.sofType===''mtx''?\"MTX \"+(state.sofBus+1):\"MIX \"+(state.sofBus+1))) : \"AUX ▸ FADERS\";\n  }\n\n  /* ================= SCREEN (canvas) ================= */\n  const cv=$(\"#screen\"), ctx=cv.getContext(\"2d\"); let W=0,H=0,DPR=1;\n  const mb=$(\"#mbridge\"), mbx=mb.getContext(\"2d\"); let MBW=0,MBH=0;\n  function sizeCanvas(){ DPR=Math.min(2,window.devicePixelRatio||1);\n    let r=cv.getBoundingClientRect(); W=r.width; H=r.height; cv.width=W*DPR; cv.height=H*DPR; ctx.setTransform(DPR,0,0,DPR,0,0);\n    r=mb.getBoundingClientRect(); MBW=r.width; MBH=r.height; mb.width=MBW*DPR; mb.height=MBH*DPR; mbx.setTransform(DPR,0,0,DPR,0,0);\n    drawScreen(); }\n  function roundRect(x,y,w,h,r){ ctx.beginPath();ctx.moveTo(x+r,y);ctx.arcTo(x+w,y,x+w,y+h,r);ctx.arcTo(x+w,y+h,x,y+h,r);ctx.arcTo(x,y+h,x,y,r);ctx.arcTo(x,y,x+w,y,r);ctx.closePath(); }\n  // hit regions\n  let hitRegions=[], activeRegion=null;\n  function reg(o){ hitRegions.push(o); return o; }\n  function inRegion(r,p){ if(r.hit===''circle'')return Math.hypot(p.x-r.cx,p.y-r.cy)<=(r.rr||12); return p.x>=r.x&&p.x<=r.x+r.w&&p.y>=r.y&&p.y<=r.y+r.h; }\n  function evtPos(e){ const r=cv.getBoundingClientRect(); return {x:e.clientX-r.left,y:e.clientY-r.top}; }\n  cv.addEventListener(\"pointerdown\",e=>{ const p=evtPos(e);\n    for(let i=hitRegions.length-1;i>=0;i--){ const r=hitRegions[i]; if(inRegion(r,p)){ if(r.onDown)r.onDown(p);\n      if(r.onDrag){ activeRegion=r; cv.setPointerCapture(e.pointerId); r.onDrag(p); } drawScreen(); e.preventDefault(); return; } } });\n  cv.addEventListener(\"pointermove\",e=>{ if(!activeRegion)return; activeRegion.onDrag(evtPos(e)); drawScreen(); e.preventDefault(); });\n  const cvUp=()=>{activeRegion=null;}; cv.addEventListener(\"pointerup\",cvUp); cv.addEventListener(\"pointercancel\",cvUp);\n\n  // screen UI primitives (Yamaha style)\n  function scrBg(){ const g=ctx.createLinearGradient(0,0,0,H); g.addColorStop(0,SC.bg1); g.addColorStop(1,SC.bg0); ctx.fillStyle=g; ctx.fillRect(0,0,W,H); }\n  function panel(x,y,w,h,title,accent){ const g=ctx.createLinearGradient(0,y,0,y+h); g.addColorStop(0,SC.panelHi); g.addColorStop(1,SC.panelLo);\n    ctx.fillStyle=g; roundRect(x,y,w,h,7); ctx.fill(); ctx.strokeStyle=accent||SC.border; ctx.lineWidth=1; roundRect(x+.5,y+.5,w-1,h-1,7); ctx.stroke();\n    if(title){ ctx.fillStyle=SC.mut; ctx.font=\"700 9px Inter,system-ui\"; ctx.textAlign=\"left\"; ctx.textBaseline=\"alphabetic\"; ctx.fillText(title,x+9,y+13); } }\n  function scrBtn(x,y,w,h,label,active,onClick,col,small){ col=col||SC.amber;\n    const g=ctx.createLinearGradient(0,y,0,y+h); if(active){ g.addColorStop(0,col); g.addColorStop(1,shade(col,-30)); } else { g.addColorStop(0,\"#333a41\"); g.addColorStop(1,\"#22272d\"); }\n    ctx.fillStyle=g; roundRect(x,y,w,h,5); ctx.fill(); ctx.strokeStyle=active?shade(col,-40):\"#454c54\"; ctx.lineWidth=1; roundRect(x+.5,y+.5,w-1,h-1,5); ctx.stroke();\n    ctx.fillStyle=active?\"#0b1420\":\"#cfe0f0\"; ctx.font=\"700 \"+(small?9:10)+\"px Inter,system-ui\"; ctx.textAlign=\"center\"; ctx.textBaseline=\"middle\"; ctx.fillText(label,x+w/2,y+h/2+.5); ctx.textBaseline=\"alphabetic\";\n    if(onClick) reg({x,y,w,h,onDown:()=>onClick()}); }\n  function shade(hex,amt){ const h=hex.replace(''#'',''''); let r=parseInt(h.substr(0,2),16),g=parseInt(h.substr(2,2),16),b=parseInt(h.substr(4,2),16);\n    r=clamp(r+amt,0,255);g=clamp(g+amt,0,255);b=clamp(b+amt,0,255); return \"#\"+[r,g,b].map(v=>v.toString(16).padStart(2,''0'')).join(''''); }\n  function scrParam(x,y,w,label,val,min,max,fmt,onSet,opts){ opts=opts||{};\n    if(label){ ctx.fillStyle=SC.mut; ctx.font=\"700 9px Inter,system-ui\"; ctx.textAlign=\"left\"; ctx.fillText(label,x,y-4); }\n    ctx.textAlign=\"right\"; ctx.fillStyle=SC.ink; ctx.font=\"800 11px Inter,system-ui\"; ctx.fillText(fmt(val),x+w,y-4);\n    const th=7; ctx.fillStyle=\"#13161b\"; roundRect(x,y,w,th,4); ctx.fill(); ctx.strokeStyle=SC.line; ctx.lineWidth=1; roundRect(x+.5,y+.5,w-1,th-1,4); ctx.stroke();\n    let t=opts.log?Math.log(Math.max(min,val)/min)/Math.log(max/min):(val-min)/(max-min); t=clamp(t,0,1);\n    ctx.fillStyle=opts.col||SC.cyan; roundRect(x,y,t*w,th,4); ctx.fill();\n    ctx.fillStyle=\"#eef4fb\"; ctx.beginPath(); ctx.arc(x+t*w,y+th/2,5.5,0,7); ctx.fill();\n    reg({x:x-4,y:y-10,w:w+8,h:th+20,onDrag:p=>{ let tt=clamp((p.x-x)/w,0,1); let v=opts.log?min*Math.pow(max/min,tt):min+tt*(max-min); if(opts.step)v=Math.round(v/opts.step)*opts.step; onSet(clamp(v,min,max)); }}); }\n  function vmeter(x,y,w,h,dbfs,peakLine){ ctx.fillStyle=\"#0b0e12\"; ctx.fillRect(x,y,w,h);\n    const t=clamp((dbfs+60)/60,0,1),hh=h*t; const g=ctx.createLinearGradient(0,y+h,0,y); g.addColorStop(0,\"#2ea85a\"); g.addColorStop(.6,\"#37c86a\"); g.addColorStop(.82,\"#e8c33a\"); g.addColorStop(1,\"#e0483f\");\n    ctx.fillStyle=g; ctx.fillRect(x,y+h-hh,w,hh);\n    if(peakLine!==false){ const ty=y+h-h*((-18+60)/60); ctx.strokeStyle=\"#ffffff40\"; ctx.lineWidth=1; ctx.beginPath(); ctx.moveTo(x,ty); ctx.lineTo(x+w,ty); ctx.stroke(); } }\n\n  function setMode(m){ state.mode=m; document.querySelectorAll(''.tab[data-mode]'').forEach(t=>t.classList.toggle(\"active\",t.dataset.mode===m)); paintSelected(); drawScreen(); }\n  document.querySelectorAll(''.tab[data-mode]'').forEach(t=>t.onclick=()=>setMode(t.dataset.mode));\n  $(\"#sofBtn\").onclick=()=>{ if(state.sof>=0){ state.sof=-1; } else { engageSof(''mix'',0); return; } updateSofUi(); paintBay(); drawScreen(); };\n\n  renderScreen=function(){ if(!W)return; hitRegions=[]; ctx.clearRect(0,0,W,H); scrBg();\n    switch(state.mode){\n      case \"selected\": drawSelCh(); break; case \"overview\": drawOverview(); break;\n      case \"eq\": drawEQ(); break; case \"gate\": drawGate(); break; case \"comp\": drawComp(); break;\n      case \"sends\": drawSends(); break; case \"dca\": drawDCA(); break; case \"fx\": drawFX(); break;\n      case \"scenes\": drawScenes(); break; case \"meter\": drawMeter(); break; default: drawSelCh();\n    }\n    drawFnAccess();\n  };\n  // function access strip (Yamaha shows scene # + selected ch top-right); minimal\n  function drawFnAccess(){ /* subtle top-right scene tag */\n    ctx.fillStyle=SC.dim; ctx.font=\"700 8px Inter,system-ui\"; ctx.textAlign=\"right\"; ctx.fillText(\"SCENE \"+String(state.scene+1).padStart(3,''0''),W-6,10); ctx.textAlign=\"left\"; }\n\n  /* ---- shared: EQ graph ---- */\n  function drawEqGraph(gx,gy,gw,gh,ch,interactive){\n    const g=ctx.createLinearGradient(0,gy,0,gy+gh); g.addColorStop(0,\"#191e26\"); g.addColorStop(1,\"#131720\");\n    ctx.fillStyle=g; roundRect(gx,gy,gw,gh,6); ctx.fill(); ctx.strokeStyle=SC.border; ctx.lineWidth=1; roundRect(gx+.5,gy+.5,gw-1,gh-1,6); ctx.stroke();\n    ctx.save(); roundRect(gx,gy,gw,gh,6); ctx.clip();\n    ctx.font=\"8px Inter\"; ctx.textAlign=\"center\";\n    [30,100,300,1000,3000,10000].forEach(f=>{ const x=gx+fx(f)*gw; ctx.strokeStyle=SC.grid; ctx.lineWidth=1; ctx.beginPath();ctx.moveTo(x,gy);ctx.lineTo(x,gy+gh);ctx.stroke();\n      ctx.fillStyle=SC.dim; ctx.fillText(f>=1000?(f/1000)+\"k\":f,x,gy+gh-3); });\n    for(let d=-18;d<=18;d+=6){ const yy=gy+gh/2-d/24*gh/2; ctx.strokeStyle=d===0?\"#3a424b\":\"#1f262e\"; ctx.beginPath();ctx.moveTo(gx,yy);ctx.lineTo(gx+gw,yy);ctx.stroke();\n      ctx.fillStyle=SC.dim; ctx.textAlign=\"left\"; ctx.fillText((d>0?\"+\":\"\")+d,gx+3,yy-2); ctx.textAlign=\"center\"; }\n    // per-band ghost curves\n    ch.eq.forEach((b,bi)=>{ if(b.g===0)return; ctx.beginPath();\n      for(let px=0;px<=gw;px+=3){ const f=fInv(px/gw),gg=biquadDb(b.type,b.f,b.g,b.q*eqTypeFactor(ch.eqType),f),yy=gy+gh/2-gg/24*gh/2; px===0?ctx.moveTo(gx,yy):ctx.lineTo(gx+px,yy); }\n      ctx.strokeStyle=SC.band[bi]+\"55\"; ctx.lineWidth=1; ctx.stroke(); });\n    // sum curve\n    ctx.beginPath();\n    for(let px=0;px<=gw;px+=2){ const f=fInv(px/gw),gg=eqMag(ch,f),yy=gy+gh/2-gg/24*gh/2; px===0?ctx.moveTo(gx,yy):ctx.lineTo(gx+px,yy); }\n    ctx.strokeStyle=ch.color; ctx.lineWidth=2.2; ctx.stroke();\n    ctx.lineTo(gx+gw,gy+gh/2); ctx.lineTo(gx,gy+gh/2); ctx.closePath(); ctx.fillStyle=ch.color+\"1c\"; ctx.fill();\n    ctx.restore();\n    // HPF marker\n    if(ch.hpfOn){ const x=gx+fx(ch.hpf)*gw; ctx.strokeStyle=SC.amber; ctx.setLineDash([4,3]); ctx.beginPath();ctx.moveTo(x,gy);ctx.lineTo(x,gy+gh);ctx.stroke(); ctx.setLineDash([]);\n      ctx.fillStyle=SC.amber; ctx.beginPath();ctx.arc(x,gy+gh-12,6,0,7);ctx.fill(); ctx.fillStyle=\"#0b1420\";ctx.font=\"700 8px Inter\";ctx.textAlign=\"center\";ctx.fillText(\"H\",x,gy+gh-9);\n      if(interactive) reg({hit:''circle'',cx:x,cy:gy+gh-12,rr:15,onDrag:p=>{ ch.hpf=clamp(Math.round(fInv((p.x-gx)/gw)),20,600); applyChanAudio(ch.i); paintSelected(); checkMissions(); }}); }\n    // band nodes (draggable)\n    ch.eq.forEach((b,bi)=>{ const x=gx+fx(b.f)*gw, yy=gy+gh/2-b.g/24*gh/2, selb=state.eqBand===bi;\n      ctx.fillStyle=SC.band[bi]; ctx.beginPath();ctx.arc(x,yy,selb?8:6.5,0,7);ctx.fill();\n      if(selb){ ctx.strokeStyle=\"#fff\"; ctx.lineWidth=1.6; ctx.stroke(); }\n      ctx.fillStyle=\"#0b1420\"; ctx.font=\"700 8px Inter\"; ctx.textAlign=\"center\"; ctx.textBaseline=\"middle\"; ctx.fillText(bi+1,x,yy); ctx.textBaseline=\"alphabetic\";\n      if(interactive) reg({hit:''circle'',cx:x,cy:yy,rr:16,onDown:()=>{state.eqBand=bi;paintSelected();},\n        onDrag:p=>{ b.f=clamp(Math.round(fInv((p.x-gx)/gw)),20,20000); b.g=clamp(-(p.y-gy-gh/2)/(gh/2)*24,-18,18); applyChanAudio(ch.i); paintSelected(); checkMissions(); }}); });\n  }\n  /* ---- shared: dynamics mini graph (for CHANNEL) ---- */\n  function drawDynMini(x,y,w,h,ch,which){\n    const isGate=which===1; const on=isGate?ch.gateOn:ch.compOn;\n    panel(x,y,w,h, isGate?\"DYNAMICS 1 · GATE\":\"DYNAMICS 2 · COMP\", on?(isGate?SC.green:SC.cyan):SC.border);\n    scrBtn(x+w-48,y+4,42,15,on?\"ON\":\"OFF\",on,()=>{ if(isGate)ch.gateOn=!ch.gateOn; else ch.compOn=!ch.compOn; applyChanAudio(ch.i); paintSelected(); checkMissions(); }, isGate?SC.green:SC.cyan,true);\n    // mini transfer\n    const px0=x+10,py0=y+24,pw=w*0.52,ph=h-34;\n    ctx.strokeStyle=SC.line; ctx.strokeRect(px0,py0,pw,ph);\n    ctx.strokeStyle=\"#343b43\"; ctx.setLineDash([3,3]); ctx.beginPath();ctx.moveTo(px0,py0+ph);ctx.lineTo(px0+pw,py0);ctx.stroke(); ctx.setLineDash([]);\n    if(isGate){ const X=d=>px0+clamp((d+72)/72,0,1)*pw, Y=o=>py0+ph-clamp((o+72)/72,0,1)*ph;\n      ctx.beginPath(); for(let d=-72;d<=0;d+=2){ const o=d>ch.gateThr?d:d+ch.gateRange; const xx=X(d),yy=Y(clamp(o,-72,0)); d===-72?ctx.moveTo(xx,yy):ctx.lineTo(xx,yy); }\n      ctx.strokeStyle=SC.green; ctx.lineWidth=2; ctx.stroke();\n      const tx=X(ch.gateThr); ctx.strokeStyle=SC.red; ctx.setLineDash([3,2]); ctx.beginPath();ctx.moveTo(tx,py0);ctx.lineTo(tx,py0+ph);ctx.stroke(); ctx.setLineDash([]);\n      reg({x:tx-12,y:py0,w:24,h:ph,onDrag:p=>{ ch.gateThr=clamp(Math.round((p.x-px0)/pw*72-72),-72,0); applyChanAudio(ch.i); paintSelected(); }});\n    } else { const ratio=ch.compRatio>=40?40:ch.compRatio; const X=d=>px0+clamp((d+60)/60,0,1)*pw, Y=o=>py0+ph-clamp((o+60)/60,0,1)*ph;\n      ctx.beginPath(); for(let d=-60;d<=0;d+=2){ let o=d>ch.compThr?ch.compThr+(d-ch.compThr)/ratio:d; o+=ch.compGain; const xx=X(d),yy=Y(clamp(o,-60,6)); d===-60?ctx.moveTo(xx,yy):ctx.lineTo(xx,yy); }\n      ctx.strokeStyle=SC.cyan; ctx.lineWidth=2; ctx.stroke();\n      const tx=X(ch.compThr); ctx.strokeStyle=SC.red; ctx.setLineDash([3,2]); ctx.beginPath();ctx.moveTo(tx,py0);ctx.lineTo(tx,py0+ph);ctx.stroke(); ctx.setLineDash([]);\n      reg({x:tx-12,y:py0,w:24,h:ph,onDrag:p=>{ ch.compThr=clamp(Math.round((p.x-px0)/pw*60-60),-54,0); applyChanAudio(ch.i); paintSelected(); }});\n    }\n    // params + GR\n    const ix=px0+pw+12, iw=x+w-ix-8; let iy=py0+4;\n    ctx.textAlign=\"left\"; ctx.font=\"700 8px Inter\";\n    if(isGate){ ctx.fillStyle=SC.mut; ctx.fillText(\"THR\",ix,iy+3); ctx.fillStyle=SC.ink; ctx.textAlign=\"right\"; ctx.fillText(ch.gateThr+\" dB\",ix+iw,iy+3); iy+=15;\n      ctx.textAlign=\"left\"; ctx.fillStyle=SC.mut; ctx.fillText(\"RANGE\",ix,iy+3); ctx.fillStyle=SC.ink; ctx.textAlign=\"right\"; ctx.fillText(ch.gateRange+\" dB\",ix+iw,iy+3); iy+=17;\n      const gr=ch._gr||0, open=gr<0.5; ctx.textAlign=\"left\"; ctx.fillStyle=open?SC.green:SC.red; ctx.beginPath();ctx.arc(ix+5,iy+2,4,0,7);ctx.fill();\n      ctx.fillStyle=SC.ink; ctx.fillText(open?\"OPEN\":\"CLOSED\",ix+14,iy+5); iy+=14;\n      ctx.fillStyle=SC.mut; ctx.fillText(\"GR\",ix,iy+5); ctx.fillStyle=\"#13161b\"; ctx.fillRect(ix+18,iy,iw-18,7); ctx.fillStyle=SC.red; ctx.fillRect(ix+18,iy,clamp(gr/60,0,1)*(iw-18),7);\n    } else { const r=ch.compRatio>=40?\"∞\":ch.compRatio.toFixed(1);\n      ctx.fillStyle=SC.mut; ctx.fillText(\"THR\",ix,iy+3); ctx.fillStyle=SC.ink; ctx.textAlign=\"right\"; ctx.fillText(ch.compThr+\" dB\",ix+iw,iy+3); iy+=15;\n      ctx.textAlign=\"left\"; ctx.fillStyle=SC.mut; ctx.fillText(\"RATIO\",ix,iy+3); ctx.fillStyle=SC.ink; ctx.textAlign=\"right\"; ctx.fillText(r+\":1\",ix+iw,iy+3); iy+=17;\n      let gr=0; if(ac&&aNodes[ch.i]&&ch.compOn) gr=-aNodes[ch.i].comp.reduction;\n      ctx.textAlign=\"left\"; ctx.fillStyle=SC.mut; ctx.fillText(\"GR \"+gr.toFixed(1),ix,iy+5); iy+=10;\n      ctx.fillStyle=\"#13161b\"; ctx.fillRect(ix,iy,iw,7); ctx.fillStyle=SC.cyan; ctx.fillRect(ix,iy,clamp(gr/24,0,1)*iw,7);\n    }\n  }\n\n  /* ================= SELECTED CHANNEL VIEW (home) ================= */\n  function drawSelCh(){\n    const ch=CH[state.sel], m=8; let y=6;\n    // HEADER\n    panel(m,y,W-2*m,40,null,ch.color);\n    ctx.fillStyle=ch.color; roundRect(m+6,y+7,26,26,4); ctx.fill();\n    ctx.fillStyle=pickInk(ch.color); ctx.font=\"800 12px Inter\"; ctx.textAlign=\"center\"; ctx.textBaseline=\"alphabetic\"; ctx.fillText(String(ch.i+1),m+19,y+24);\n    ctx.textAlign=\"left\"; ctx.fillStyle=SC.ink; ctx.font=\"800 15px Inter\"; ctx.fillText(ch.name,m+40,y+18);\n    ctx.fillStyle=SC.mut; ctx.font=\"700 9px Inter\"; ctx.fillText(\"CH \"+(ch.i+1)+\"  ·  INPUT\",m+40,y+31);\n    let hx=m+184;\n    ctx.fillStyle=SC.mut; ctx.font=\"700 8px Inter\"; ctx.fillText(\"HA\",hx,y+13);\n    ctx.fillStyle=SC.ink; ctx.font=\"800 14px Inter\"; ctx.fillText((ch.gain>0?\"+\":\"\")+ch.gain.toFixed(0)+\" dB\",hx,y+30);\n    scrBtn(hx+70,y+6,24,15,\"Ø\",ch.phase,()=>{ch.phase=!ch.phase;applyChanAudio(ch.i);paintSelected();},SC.amber,true);\n    scrBtn(hx+70,y+24,24,13,\"GT\",false,()=>toast(\"Gain Tracking (DiGiCo)\"),SC.cyan,true);\n    scrBtn(hx+97,y+6,34,15,\"+48V\",ch.phantom,()=>{ch.phantom=!ch.phantom;paintSelected();},SC.red,true);\n    scrBtn(hx+97,y+24,34,13,ch.eqType.slice(0,4),false,()=>{ const arr=[\"PRECISE\",\"AGGRESSIVE\",\"SMOOTH\",\"LEGACY\"]; ch.eqType=arr[(arr.indexOf(ch.eqType)+1)%4]; applyChanAudio(ch.i); },SC.amber,true);\n    ctx.textAlign=\"right\"; ctx.fillStyle=ch.on?SC.green:SC.dim; ctx.font=\"800 13px Inter\"; ctx.fillText(faderTxt(ch.fader)+\" dB\",W-m-66,y+26); ctx.textAlign=\"left\";\n    scrBtn(W-m-58,y+7,50,26,ch.on?\"ON\":\"MUTE\",ch.on,()=>{ch.on=!ch.on;applyChanAudio(ch.i);paintBay();checkMissions();},ch.on?SC.green:SC.red);\n    y+=46;\n    const mainH=H-y-6;\n    const gx=m, gw=W*0.545-m; const ghEq=mainH*0.52, hpfH=32, panH=30, sendH=mainH-ghEq-hpfH-panH-18;\n    // EQ\n    drawEqGraph(gx,y,gw,ghEq,ch,true);\n    ctx.fillStyle=SC.mut; ctx.font=\"700 8px Inter\"; ctx.textAlign=\"left\"; ctx.fillText(\"EQUALIZER  ·  \"+ch.eqType,gx+6,y+11);\n    // HPF row\n    let hy=y+ghEq+6;\n    panel(gx,hy,gw,hpfH,null);\n    scrBtn(gx+6,hy+7,52,18,\"HPF \"+(ch.hpfOn?\"ON\":\"OFF\"),ch.hpfOn,()=>{ch.hpfOn=!ch.hpfOn;applyChanAudio(ch.i);paintSelected();checkMissions();},SC.amber,true);\n    scrParam(gx+72,hy+22,gw-150,\"HPF\",ch.hpf,20,600,v=>Math.round(v)+\" Hz\",v=>{ch.hpf=Math.round(v);ch.hpfOn=true;applyChanAudio(ch.i);paintSelected();checkMissions();},{log:true,col:SC.amber});\n    scrBtn(gx+gw-72,hy+7,66,18,\"−12 dB/oct\",false,()=>{},SC.amber,true);\n    // PAN + TO ST row\n    let py=hy+hpfH+6;\n    panel(gx,py,gw,panH,null);\n    ctx.fillStyle=SC.mut; ctx.font=\"700 8px Inter\"; ctx.textAlign=\"left\"; ctx.fillText(\"PAN\",gx+6,py+11);\n    const pbx=gx+34,pbw=gw*0.5,pby=py+panH/2+2;\n    ctx.fillStyle=\"#13161b\"; ctx.fillRect(pbx,pby-3,pbw,6); ctx.fillStyle=\"#3a424b\"; ctx.fillRect(pbx+pbw/2-0.5,pby-6,1,12);\n    const pn=clamp((ch.pan+63)/126,0,1); ctx.fillStyle=ch.color; ctx.beginPath();ctx.arc(pbx+pn*pbw,pby,5,0,7);ctx.fill();\n    reg({x:pbx-4,y:pby-10,w:pbw+8,h:20,onDrag:p=>{ ch.pan=clamp(Math.round(((p.x-pbx)/pbw)*126-63),-63,63); applyChanAudio(ch.i); paintSelected(); }});\n    ctx.fillStyle=SC.ink; ctx.font=\"800 10px Inter\"; ctx.textAlign=\"right\"; ctx.fillText(panTxt(ch.pan),pbx+pbw+30,pby+3); ctx.textAlign=\"left\";\n    scrBtn(gx+gw-70,py+6,64,panH-12,\"TO ST\",true,()=>{},SC.green,true);\n    // SENDS mini (MIX 1-8)\n    let sy=py+panH+6;\n    panel(gx,sy,gw,sendH,\"SEND  ·  MIX 1-8\");\n    const perRow=4, cellW=(gw-16)/perRow, cellH=(sendH-16)/2;\n    for(let mixn=0;mixn<8;mixn++){ const col=mixn%perRow,row=Math.floor(mixn/perRow); const cxp=gx+8+col*cellW, cyp=sy+16+row*cellH;\n      const ons=ch.sendOn[mixn]; ctx.fillStyle=ons?SC.cyan:\"#333a42\"; ctx.beginPath();ctx.arc(cxp+5,cyp+cellH/2,4,0,7);ctx.fill();\n      reg({hit:''circle'',cx:cxp+5,cy:cyp+cellH/2,rr:9,onDown:()=>{ch.sendOn[mixn]=!ch.sendOn[mixn];checkMissions();}});\n      ctx.fillStyle=ons?SC.ink:SC.dim; ctx.font=\"700 8px Inter\"; ctx.textAlign=\"left\"; ctx.fillText(\"MIX\"+(mixn+1),cxp+13,cyp+cellH/2-1);\n      ctx.fillStyle=ons?SC.cyan:SC.dim; ctx.fillText(ons?faderTxt(ch.sends[mixn]):\"−∞\",cxp+13,cyp+cellH/2+9);\n    }\n    // right column dynamics\n    const rx=W*0.545+2, rw=W-rx-m, dh=(mainH-6)/2;\n    drawDynMini(rx,y,rw,dh,ch,1);\n    drawDynMini(rx,y+dh+6,rw,dh,ch,2);\n  }\n\n  /* ================= OVERVIEW ================= */\n  function drawOverview(){\n    const base=Math.floor(state.sel/8)*8; const n=8,pad=6,gw=(W-pad*2)/n;\n    for(let s=0;s<n;s++){ const ci=base+s; if(ci>=24){ continue; } const ch=CH[ci]; const x=pad+s*gw,yy=6,w=gw-5,h=H-12; const cx=x+5,cw=w-10;\n      const g=ctx.createLinearGradient(0,yy,0,yy+h); g.addColorStop(0,SC.panelHi); g.addColorStop(1,SC.panelLo);\n      ctx.fillStyle=g; roundRect(x,yy,w,h,7); ctx.fill(); ctx.strokeStyle=ci===state.sel?SC.amber:SC.border; ctx.lineWidth=ci===state.sel?2:1; roundRect(x+.5,yy+.5,w-1,h-1,7); ctx.stroke();\n      ctx.fillStyle=ch.color; roundRect(x,yy,w,16,7); ctx.fill(); ctx.fillRect(x,yy+9,w,7);\n      ctx.fillStyle=pickInk(ch.color); ctx.font=\"800 9px Inter\"; ctx.textAlign=\"center\"; ctx.fillText(ch.name.slice(0,11),x+w/2,yy+11);\n      reg({x,y:yy,w,h:h,onDown:()=>selectChannel(ci)});\n      // EQ thumb\n      const eqY=yy+20,eqH=44; ctx.fillStyle=\"#131720\"; roundRect(cx,eqY,cw,eqH,4); ctx.fill(); ctx.strokeStyle=SC.line; roundRect(cx+.5,eqY+.5,cw-1,eqH-1,4); ctx.stroke();\n      const midE=eqY+eqH/2; ctx.strokeStyle=SC.grid; ctx.beginPath();ctx.moveTo(cx,midE);ctx.lineTo(cx+cw,midE);ctx.stroke();\n      ctx.beginPath(); for(let px=0;px<=cw;px+=2){ const f=fInv(px/cw); const yv=clamp(midE-clamp(eqMag(ch,f)/18,-1,1)*(eqH*0.4),eqY+2,eqY+eqH-2); px===0?ctx.moveTo(cx,yv):ctx.lineTo(cx+px,yv); }\n      ctx.strokeStyle=ch.color; ctx.lineWidth=1.5; ctx.stroke();\n      ctx.fillStyle=SC.dim; ctx.font=\"700 7px Inter\"; ctx.textAlign=\"left\"; ctx.fillText(\"EQ\",cx+3,eqY+8);\n      // dyn row\n      let dyv=eqY+eqH+11; const inDb=(playing&&ch.hasAudio)?chLevelDb(ch.i):ch.src+ch.g