lStyle=ch.gateOn?SC.ink:SC.dim; ctx.font=\"700 7.5px Inter\"; ctx.fillText(\"GATE\",cx+11,dyv+3);\n      ctx.fillStyle=ch.compOn?SC.cyan:\"#2a3f56\"; ctx.beginPath();ctx.arc(cx+cw*0.55,dyv,3.5,0,7);ctx.fill();\n      ctx.fillStyle=ch.compOn?SC.ink:SC.dim; ctx.fillText(\"COMP\",cx+cw*0.55+6,dyv+3);\n      dyv+=13; ctx.fillStyle=ch.hpfOn?SC.amber:SC.dim; ctx.fillText(ch.hpfOn?(\"HPF \"+ch.hpf):\"HPF —\",cx,dyv+3);\n      // pan bar\n      dyv+=12; const pbw=cw; ctx.fillStyle=\"#0d0e11\"; ctx.fillRect(cx,dyv,pbw,4); ctx.fillStyle=\"#3b3e45\"; ctx.fillRect(cx+pbw/2-0.5,dyv-2,1,8);\n      const pn=clamp((ch.pan+63)/126,0,1); ctx.fillStyle=ch.color; ctx.beginPath();ctx.arc(cx+pn*pbw,dyv+2,3,0,7);ctx.fill();\n      // fader + meter\n      const fzTop=dyv+12,fzBot=yy+h-24; const railX=cx+cw*0.34;\n      ctx.fillStyle=\"#0b0c0e\"; roundRect(railX-3,fzTop,6,fzBot-fzTop,3); ctx.fill();\n      const uY=fzBot-db2pos(0)*(fzBot-fzTop); ctx.strokeStyle=\"#3b3e45\"; ctx.setLineDash([3,3]); ctx.beginPath();ctx.moveTo(railX-8,uY);ctx.lineTo(railX+cw*0.28,uY);ctx.stroke(); ctx.setLineDash([]);\n      const capY=fzBot-db2pos(ch.fader)*(fzBot-fzTop),capW=cw*0.44,capX=railX-capW/2;\n      ctx.fillStyle=ch.on?\"#22242a\":\"#151619\"; roundRect(capX,capY-8,capW,16,3); ctx.fill(); ctx.strokeStyle=ch.on?ch.color:\"#43464d\"; ctx.lineWidth=1.4; roundRect(capX,capY-8,capW,16,3); ctx.stroke();\n      ctx.fillStyle=ch.on?\"#dbe4f2\":\"#5a6b88\"; ctx.fillRect(capX+2,capY-1,capW-4,2);\n      reg({x:capX-6,y:fzTop-4,w:capW+12,h:fzBot-fzTop+12,onDrag:p=>{ ch.fader=pos2db(1-(p.y-fzTop)/(fzBot-fzTop)); applyChanAudio(ch.i); paintBay(); checkMissions(); }});\n      vmeter(railX+cw*0.30,fzTop,7,fzBot-fzTop,inDb);\n      ctx.fillStyle=SC.ink; ctx.font=\"800 9px Inter\"; ctx.textAlign=\"left\"; ctx.fillText(faderTxt(ch.fader),cx,yy+h-8);\n      // ON button\n      if(!ch.on){ ctx.fillStyle=\"rgba(30,6,10,.5)\"; roundRect(x,yy,w,h,7); ctx.fill(); ctx.fillStyle=SC.red; ctx.font=\"800 11px Inter\"; ctx.textAlign=\"center\"; ctx.fillText(\"MUTE\",x+w/2,yy+h/2); }\n      scrBtn(x+w-30,yy+h-16,26,12,\"ON\",ch.on,()=>{ch.on=!ch.on;applyChanAudio(ch.i);paintBay();},ch.on?SC.green:SC.red,true);\n    }\n  }\n\n  /* ================= EQ (full page) ================= */\n  function drawEQ(){\n    const ch=CH[state.sel], m=8; const gx=m,gy=6,gw=W*0.62-m,gh=H-12;\n    drawEqGraph(gx,gy,gw,gh,ch,true);\n    ctx.fillStyle=ch.color; ctx.font=\"800 12px Inter\"; ctx.textAlign=\"left\"; ctx.fillText(\"EQ · \"+ch.name,gx+8,gy+14);\n    const rx=gx+gw+8, rw=W-rx-m; let yy=gy+2;\n    ctx.fillStyle=SC.mut; ctx.font=\"700 9px Inter\"; ctx.fillText(\"4-BAND PARAMETRIC · CH\"+(ch.i+1),rx,yy+10); yy+=20;\n    const bw=(rw-9)/4, bn=[\"LOW\",\"LO-MID\",\"HI-MID\",\"HIGH\"];\n    bn.forEach((nm,bi)=>scrBtn(rx+bi*(bw+3),yy,bw,20,nm,state.eqBand===bi,()=>{state.eqBand=bi;paintSelected();},SC.band[bi],true)); yy+=28;\n    const b=ch.eq[state.eqBand];\n    scrParam(rx,yy+12,rw,\"FREQUENCY\",b.f,20,20000,v=>Math.round(v)+\" Hz\",v=>{b.f=Math.round(v);applyChanAudio(ch.i);paintSelected();},{log:true,col:SC.band[state.eqBand]}); yy+=32;\n    scrParam(rx,yy+12,rw,\"GAIN\",b.g,-18,18,v=>(v>0?\"+\":\"\")+v.toFixed(1)+\" dB\",v=>{b.g=v;applyChanAudio(ch.i);paintSelected();checkMissions();},{col:SC.band[state.eqBand]}); yy+=32;\n    scrParam(rx,yy+12,rw,\"Q\",b.q,0.10,10,v=>v.toFixed(2),v=>{b.q=v;applyChanAudio(ch.i);paintSelected();},{log:true,col:SC.band[state.eqBand]}); yy+=34;\n    if(state.eqBand===0){ scrBtn(rx,yy,rw/2-3,20,\"L.SHELF\",b.type===''lowshelf'',()=>{b.type=''lowshelf'';applyChanAudio(ch.i);},SC.band[0],true); scrBtn(rx+rw/2+3,yy,rw/2-3,20,\"BELL\",b.type===''peaking'',()=>{b.type=''peaking'';applyChanAudio(ch.i);},SC.band[0],true); yy+=26; }\n    else if(state.eqBand===3){ scrBtn(rx,yy,rw/2-3,20,\"H.SHELF\",b.type===''highshelf'',()=>{b.type=''highshelf'';applyChanAudio(ch.i);},SC.band[3],true); scrBtn(rx+rw/2+3,yy,rw/2-3,20,\"BELL\",b.type===''peaking'',()=>{b.type=''peaking'';applyChanAudio(ch.i);},SC.band[3],true); yy+=26; }\n    else { ctx.fillStyle=SC.dim; ctx.font=\"9px Inter\"; ctx.fillText(\"Banda BELL (paramétrica)\",rx,yy+13); yy+=26; }\n    scrBtn(rx,yy,rw/2-3,20,\"HPF \"+(ch.hpfOn?ch.hpf+\"Hz\":\"OFF\"),ch.hpfOn,()=>{ch.hpfOn=!ch.hpfOn;applyChanAudio(ch.i);paintSelected();},SC.amber,true);\n    scrBtn(rx+rw/2+3,yy,rw/2-3,20,\"LPF \"+(ch.lpfOn?\"ON\":\"OFF\"),ch.lpfOn,()=>{ch.lpfOn=!ch.lpfOn;applyChanAudio(ch.i);},\"#8f7dff\",true); yy+=28;\n    ctx.fillStyle=SC.mut; ctx.font=\"700 9px Inter\"; ctx.fillText(\"EQ TYPE\",rx,yy+2); yy+=6;\n    const tw=(rw-9)/4; [\"PRECISE\",\"AGGRESSIVE\",\"SMOOTH\",\"LEGACY\"].forEach((tp,ti)=>scrBtn(rx+ti*(tw+3),yy,tw,20,tp.slice(0,4),ch.eqType===tp,()=>{ch.eqType=tp;applyChanAudio(ch.i);},SC.cyan,true));\n  }\n\n  /* ================= DYN1 GATE (full) ================= */\n  function drawGate(){\n    const ch=CH[state.sel],m=8,gx=m,gy=6,gw=W*0.52-m,gh=H-12;\n    panel(gx,gy,gw,gh,\"DYNAMICS 1 · GATE — \"+ch.name);\n    const px0=gx+34,py0=gy+26,pw=gw-58,ph=gh-56;\n    const X=d=>px0+clamp((d+72)/72,0,1)*pw, Y=o=>py0+ph-clamp((o+72)/72,0,1)*ph;\n    ctx.strokeStyle=SC.line; ctx.strokeRect(px0,py0,pw,ph);\n    ctx.strokeStyle=\"#3b3e45\"; ctx.setLineDash([3,3]); ctx.beginPath();ctx.moveTo(X(-72),Y(-72));ctx.lineTo(X(0),Y(0));ctx.stroke(); ctx.setLineDash([]);\n    ctx.beginPath(); for(let d=-72;d<=0;d+=1){ const o=d>ch.gateThr?d:d+ch.gateRange; const xx=X(d),yy=Y(clamp(o,-90,0)); d===-72?ctx.moveTo(xx,yy):ctx.lineTo(xx,yy); }\n    ctx.strokeStyle=SC.green; ctx.lineWidth=2.2; ctx.stroke();\n    const tx=X(ch.gateThr); ctx.strokeStyle=SC.red; ctx.setLineDash([4,3]); ctx.beginPath();ctx.moveTo(tx,py0);ctx.lineTo(tx,py0+ph);ctx.stroke(); ctx.setLineDash([]);\n    ctx.fillStyle=SC.red; ctx.font=\"700 9px Inter\"; ctx.textAlign=\"center\"; ctx.fillText(\"THR\",tx,py0-2);\n    reg({x:tx-14,y:py0,w:28,h:ph,onDrag:p=>{ ch.gateThr=clamp(Math.round((p.x-px0)/pw*72-72),-72,0); applyChanAudio(ch.i); paintSelected(); }});\n    ctx.fillStyle=SC.dim; ctx.font=\"8px Inter\"; ctx.fillText(\"ENTRADA (dB)\",px0+pw/2,py0+ph+12);\n    const rx=gx+gw+8,rw=W-rx-m; panel(rx,gy,rw,gh,null); let yy=gy+8;\n    ctx.fillStyle=SC.ink; ctx.font=\"800 11px Inter\"; ctx.textAlign=\"left\"; ctx.fillText(\"GATE\",rx+12,yy+9);\n    scrBtn(rx+rw-60,yy,50,18,ch.gateOn?\"ON\":\"OFF\",ch.gateOn,()=>{ch.gateOn=!ch.gateOn;applyChanAudio(ch.i);paintSelected();checkMissions();},SC.green,true); yy+=28;\n    const gr=ch._gr||0,open=gr<0.5; ctx.fillStyle=ch.gateOn?(open?SC.green:SC.red):\"#2a3f56\"; ctx.beginPath();ctx.arc(rx+18,yy+5,6,0,7);ctx.fill();\n    ctx.fillStyle=SC.ink; ctx.font=\"700 10px Inter\"; ctx.fillText(ch.gateOn?(open?\"OPEN\":\"CLOSED\"):\"—\",rx+30,yy+8);\n    ctx.fillStyle=\"#0d0e11\"; ctx.fillRect(rx+rw-74,yy,64,9); ctx.fillStyle=SC.red; ctx.fillRect(rx+rw-74,yy,clamp(gr/60,0,1)*64,9); yy+=26;\n    scrParam(rx+12,yy+12,rw-24,\"THRESHOLD\",ch.gateThr,-72,0,v=>v+\" dB\",v=>{ch.gateThr=Math.round(v);applyChanAudio(ch.i);paintSelected();}); yy+=30;\n    scrParam(rx+12,yy+12,rw-24,\"RANGE\",ch.gateRange,-70,0,v=>(v<=-70?\"−∞\":v)+\" dB\",v=>{ch.gateRange=Math.round(v);applyChanAudio(ch.i);}); yy+=30;\n    scrParam(rx+12,yy+12,rw-24,\"ATTACK\",ch.gateAtk,0,120,v=>v.toFixed(0)+\" ms\",v=>{ch.gateAtk=v;}); yy+=30;\n    scrParam(rx+12,yy+12,rw-24,\"HOLD\",ch.gateHold,0.02,1960,v=>(v>=1000?(v/1000).toFixed(2)+\"s\":v.toFixed(0)+\"ms\"),v=>{ch.gateHold=v;},{log:true}); yy+=30;\n    scrParam(rx+12,yy+12,rw-24,\"DECAY\",ch.gateDecay,5,42300,v=>(v>=1000?(v/1000).toFixed(1)+\"s\":v.toFixed(0)+\"ms\"),v=>{ch.gateDecay=v;},{log:true});\n  }\n\n  /* ================= DYN2 COMP (full) ================= */\n  function drawComp(){\n    const ch=CH[state.sel],m=8,gx=m,gy=6,gw=W*0.52-m,gh=H-12;\n    panel(gx,gy,gw,gh,\"DYNAMICS 2 · COMPRESSOR — \"+ch.name);\n    const px0=gx+34,py0=gy+26,pw=gw-58,ph=gh-56;\n    const X=d=>px0+clamp((d+60)/60,0,1)*pw, Y=o=>py0+ph-clamp((o+60)/60,0,1)*ph;\n    ctx.strokeStyle=SC.line; ctx.strokeRect(px0,py0,pw,ph);\n    ctx.strokeStyle=\"#3b3e45\"; ctx.setLineDash([3,3]); ctx.beginPath();ctx.moveTo(X(-60),Y(-60));ctx.lineTo(X(0),Y(0));ctx.stroke(); ctx.setLineDash([]);\n    const kneeDb=(ch.compKnee===''HARD''||ch.compKnee===0)?0:ch.compKnee*4, ratio=ch.compRatio>=40?40:ch.compRatio;\n    const compFn=d=>{ const t=ch.compThr; let o; if(kneeDb>0&&d>t-kneeDb/2&&d<t+kneeDb/2){ const xk=d-(t-kneeDb/2); o=d+(1/ratio-1)*xk*xk/(2*kneeDb); } else o=d>t?t+(d-t)/ratio:d; return o+ch.compGain; };\n    ctx.beginPath(); for(let d=-60;d<=0;d+=1){ const xx=X(d),yy=Y(clamp(compFn(d),-60,6)); d===-60?ctx.moveTo(xx,yy):ctx.lineTo(xx,yy); }\n    ctx.strokeStyle=SC.cyan; ctx.lineWidth=2.2; ctx.stroke();\n    const tx=X(ch.compThr); ctx.strokeStyle=SC.red; ctx.setLineDash([4,3]); ctx.beginPath();ctx.moveTo(tx,py0);ctx.lineTo(tx,py0+ph);ctx.stroke(); ctx.setLineDash([]);\n    ctx.fillStyle=SC.red; ctx.font=\"700 9px Inter\"; ctx.textAlign=\"center\"; ctx.fillText(\"THR\",tx,py0-2);\n    reg({x:tx-14,y:py0,w:28,h:ph,onDrag:p=>{ ch.compThr=clamp(Math.round((p.x-px0)/pw*60-60),-54,0); applyChanAudio(ch.i); paintSelected(); checkMissions(); }});\n    ctx.fillStyle=SC.dim; ctx.font=\"8px Inter\"; ctx.fillText(\"ENTRADA (dB)\",px0+pw/2,py0+ph+12);\n    const rx=gx+gw+8,rw=W-rx-m; panel(rx,gy,rw,gh,null); let yy=gy+8;\n    ctx.fillStyle=SC.ink; ctx.font=\"800 11px Inter\"; ctx.textAlign=\"left\"; ctx.fillText(\"COMP\",rx+12,yy+9);\n    scrBtn(rx+rw-60,yy,50,18,ch.compOn?\"ON\":\"OFF\",ch.compOn,()=>{ch.compOn=!ch.compOn;applyChanAudio(ch.i);paintSelected();checkMissions();},SC.cyan,true); yy+=26;\n    let gr=0; if(ac&&aNodes[ch.i]&&ch.compOn) gr=-aNodes[ch.i].comp.reduction;\n    ctx.fillStyle=SC.mut; ctx.font=\"8px Inter\"; ctx.fillText(\"GR \"+gr.toFixed(1)+\" dB\",rx+12,yy+8);\n    ctx.fillStyle=\"#0d0e11\"; ctx.fillRect(rx+78,yy,rw-90,9); ctx.fillStyle=SC.cyan; ctx.fillRect(rx+78,yy,clamp(gr/24,0,1)*(rw-90),9); yy+=24;\n    scrParam(rx+12,yy+12,rw-24,\"THRESHOLD\",ch.compThr,-54,0,v=>v+\" dB\",v=>{ch.compThr=Math.round(v);applyChanAudio(ch.i);paintSelected();}); yy+=30;\n    scrParam(rx+12,yy+12,rw-24,\"RATIO\",ratio,1,40,v=>(v>=40?\"∞\":v.toFixed(1))+\":1\",v=>{ch.compRatio=v;applyChanAudio(ch.i);}); yy+=30;\n    scrParam(rx+12,yy+12,rw-24,\"ATTACK\",ch.compAtk,0,120,v=>v.toFixed(0)+\" ms\",v=>{ch.compAtk=v;applyChanAudio(ch.i);}); yy+=30;\n    scrParam(rx+12,yy+12,rw-24,\"RELEASE\",ch.compRel,5,42300,v=>(v>=1000?(v/1000).toFixed(1)+\"s\":v.toFixed(0)+\"ms\"),v=>{ch.compRel=v;applyChanAudio(ch.i);},{log:true}); yy+=30;\n    scrParam(rx+12,yy+12,rw-24,\"OUT GAIN\",ch.compGain,0,18,v=>\"+\"+v.toFixed(1)+\" dB\",v=>{ch.compGain=v;applyChanAudio(ch.i);}); yy+=28;\n    ctx.fillStyle=SC.mut; ctx.font=\"700 9px Inter\"; ctx.fillText(\"KNEE\",rx+12,yy+2); const kw=(rw-24-15)/6;\n    [\"HARD\",\"1\",\"2\",\"3\",\"4\",\"5\"].forEach((kn,ki)=>{ const val=ki===0?''HARD'':ki; const act=(ch.compKnee===val)||(ki===0&&(ch.compKnee===''HARD''||ch.compKnee===0)); scrBtn(rx+12+ki*(kw+3),yy+6,kw,18,kn,act,()=>{ch.compKnee=val;applyChanAudio(ch.i);},SC.cyan,true); });\n  }\n\n  /* ================= SENDS ON FADER page ================= */\n  function drawSends(){\n    const ch=CH[state.sel];\n    ctx.fillStyle=ch.color; ctx.font=\"800 12px Inter\"; ctx.textAlign=\"left\"; ctx.fillText(\"SENDS — \"+ch.name+\" (CH\"+(ch.i+1)+\")\",10,16);\n    scrBtn(W-150,4,68,18,\"MIX 1-16\",true,()=>{},SC.cyan,true); scrBtn(W-78,4,68,18,\"MTX 1-6\",false,()=>toast(\"Sends p/ MATRIX 1-6\"),SC.cyan,true);\n    const cols=2,rows=8,top=26,cw=(W-20-10)/cols,rh=(H-top-6)/rows;\n    for(let mn=0;mn<N_MIX;mn++){ const col=Math.floor(mn/rows),row=mn%rows; const x=10+col*(cw+10),yy=top+row*rh,on=ch.sendOn[mn];\n      ctx.fillStyle=on?SC.cyan:\"#2c2f35\"; ctx.beginPath();ctx.arc(x+8,yy+rh/2,5,0,7);ctx.fill();\n      reg({hit:''circle'',cx:x+8,cy:yy+rh/2,rr:10,onDown:()=>{ch.sendOn[mn]=!ch.sendOn[mn];checkMissions();}});\n      ctx.fillStyle=on?SC.ink:SC.dim; ctx.font=\"700 9px Inter\"; ctx.textAlign=\"left\"; ctx.fillText(MIX_NAMES[mn],x+18,yy+rh/2-3);\n      const bx=x+18,bw=cw-104,by=yy+rh/2+2,bh=6; ctx.fillStyle=\"#0d0e11\"; roundRect(bx,by,bw,bh,3); ctx.fill();\n      const t=clamp((ch.sends[mn]-FMIN)/(FMAX-FMIN),0,1); ctx.fillStyle=on?SC.cyan:\"#4a4d54\"; roundRect(bx,by,t*bw,bh,3); ctx.fill();\n      reg({x:bx-3,y:by-7,w:bw+6,h:bh+14,onDrag:p=>{ let tt=clamp((p.x-bx)/bw,0,1); ch.sends[mn]=Math.round(FMIN+tt*(FMAX-FMIN)); if(ch.sends[mn]>FMIN)ch.sendOn[mn]=true; checkMissions(); }});\n      ctx.fillStyle=on?SC.ink:SC.dim; ctx.font=\"700 9px Inter\"; ctx.textAlign=\"right\"; ctx.fillText(faderTxt(ch.sends[mn]),x+cw-42,yy+rh/2+2);\n      scrBtn(x+cw-38,yy+rh/2-8,34,16,ch.sendPre[mn]?\"PRE\":\"POST\",ch.sendPre[mn],()=>{ch.sendPre[mn]=!ch.sendPre[mn];},SC.amber,true);\n    }\n  }\n\n  /* ================= DCA / MUTE ================= */\n  function drawDCA(){\n    const ch=CH[state.sel];\n    ctx.fillStyle=SC.mut; ctx.font=\"700 10px Inter\"; ctx.textAlign=\"left\"; ctx.fillText(\"DCA GROUPS 1-8 (masters) — arraste o ganho, toque ON/MUTE\",10,14);\n    const n=N_DCA,top=20,gh=H*0.40,gapx=6,fw=(W-20-(n-1)*gapx)/n;\n    for(let g=0;g<n;g++){ const x=10+g*(fw+gapx),yy=top,fh=gh-28,fcx=x+fw/2;\n      ctx.fillStyle=\"#0d0e11\"; roundRect(fcx-3,yy,6,fh,3); ctx.fill(); ctx.strokeStyle=SC.line; roundRect(fcx-3+.5,yy+.5,6,fh,3); ctx.stroke();\n      const t=db2pos(state.dcaGain[g]),capY=yy+fh-t*fh; ctx.fillStyle=SC.amber; ctx.fillRect(fcx-7,capY-3,14,6);\n      reg({x,y:yy,w:fw,h:fh,onDrag:p=>{ state.dcaGain[g]=pos2db(clamp(1-(p.y-yy)/fh,0,1)); for(let i=0;i<N_CH;i++)if(CH[i].dca[g])applyChanAudio(i); paintBay(); }});\n      ctx.fillStyle=SC.mut; ctx.font=\"700 8px Inter\"; ctx.textAlign=\"center\"; ctx.fillText(\"DCA\"+(g+1),fcx,yy+fh+9);\n      scrBtn(x,yy+fh+11,fw,15,state.dcaOn[g]?\"ON\":\"MUTE\",state.dcaOn[g],()=>{state.dcaOn[g]=!state.dcaOn[g];for(let i=0;i<N_CH;i++)if(CH[i].dca[g])applyChanAudio(i);paintBay();},state.dcaOn[g]?SC.green:SC.red,true);\n    }\n    let yy=top+gh+8; ctx.fillStyle=ch.color; ctx.font=\"800 11px Inter\"; ctx.textAlign=\"left\"; ctx.fillText(ch.name+\" → DCA assign\",10,yy); yy+=6;\n    const bw=(W-20-15*(N_DCA-1))/N_DCA; for(let g=0;g<N_DCA;g++) scrBtn(10+g*(bw+15),yy,bw,20,\"DCA \"+(g+1),ch.dca[g],()=>{ch.dca[g]=!ch.dca[g];applyChanAudio(ch.i);},SC.amber,true);\n    yy+=30; ctx.fillStyle=SC.mut; ctx.font=\"700 10px Inter\"; ctx.fillText(\"MUTE GROUPS 1-6 — mute-master (vermelho) · abaixo: pertinência do canal\",10,yy); yy+=6;\n    const mw=(W-20-7*(N_MUTE-1))/N_MUTE; for(let g=0;g<N_MUTE;g++){ const x=10+g*(mw+7);\n      scrBtn(x,yy,mw,20,\"MUTE \"+(g+1),state.muteActive[g],()=>{state.muteActive[g]=!state.muteActive[g];for(let i=0;i<N_CH;i++)if(CH[i].mute[g])applyChanAudio(i);paintBay();},SC.red,true);\n      scrBtn(x,yy+24,mw,16,ch.mute[g]?\"CH IN\":\"assign\",ch.mute[g],()=>{ch.mute[g]=!ch.mute[g];applyChanAudio(ch.i);},\"#4a6285\",true); }\n  }\n\n  /* ================= RACK (FX) ================= */\n  function drawFX(){\n    const ch=CH[state.sel],half=(W-20-10)/2;\n    panel(10,6,half,H-12,\"RACK 1 · REVERB (Hall)\"); let yy=40;\n    scrParam(22,yy,half-24,\"MIX (return)\",state.fx.revMix,0,1,v=>Math.round(v*100)+\"%\",v=>{state.fx.revMix=v;applyFX();paintRightRack();}); yy+=34;\n    scrParam(22,yy,half-24,\"SIZE (decay)\",state.fx.revSize,0.3,4,v=>v.toFixed(1)+\" s\",v=>{state.fx.revSize=v; if(fxRack)fxRack.conv.buffer=makeImpulse(v);}); yy+=40;\n    ctx.fillStyle=SC.mut; ctx.font=\"700 9px Inter\"; ctx.textAlign=\"left\"; ctx.fillText(ch.name+\" → REVERB send\",22,yy);\n    scrParam(22,yy+14,half-24,\"\",ch.fxRev,FMIN,FMAX,v=>faderTxt(v)+\" dB\",v=>{ch.fxRev=Math.round(v);applyChanAudio(ch.i);},{col:SC.cyan});\n    const dx=10+half+10; panel(dx,6,half,H-12,\"RACK 2 · DELAY\"); yy=40;\n    scrParam(dx+12,yy,half-24,\"TIME\",state.fx.dlyTime,0.05,1.2,v=>Math.round(v*1000)+\" ms\",v=>{state.fx.dlyTime=v;applyFX();}); yy+=34;\n    scrParam(dx+12,yy,half-24,\"FEEDBACK\",state.fx.dlyFb,0,0.85,v=>Math.round(v*100)+\"%\",v=>{state.fx.dlyFb=v;applyFX();}); yy+=34;\n    scrParam(dx+12,yy,half-24,\"MIX (return)\",state.fx.dlyMix,0,1,v=>Math.round(v*100)+\"%\",v=>{state.fx.dlyMix=v;applyFX();}); yy+=40;\n    ctx.fillStyle=SC.mut; ctx.font=\"700 9px Inter\"; ctx.fillText(ch.name+\" → DELAY send\",dx+12,yy);\n    scrParam(dx+12,yy+14,half-24,\"\",ch.fxDly,FMIN,FMAX,v=>faderTxt(v)+\" dB\",v=>{ch.fxDly=Math.round(v);applyChanAudio(ch.i);},{col:SC.cyan});\n  }\n\n  /* ================= SCENE ================= */\n  function drawScenes(){\n    ctx.fillStyle=SC.mut; ctx.font=\"700 10px Inter\"; ctx.textAlign=\"left\"; ctx.fillText(\"SCENES / SNAPSHOTS — STORE/RECALL (recall total). X32 real: até 100 cenas.\",10,14);\n    const cols=2,rows=5,top=24,gapx=10,gapy=7,cw=(W-20-gapx)/cols,rh=(H-top-6-gapy*(rows-1))/rows;\n    for(let s=0;s<10;s++){ const col=Math.floor(s/rows),row=s%rows; const x=10+col*(cw+gapx),yy=top+row*(rh+gapy),sc=scenes[s];\n      panel(x,yy,cw,rh, null, s===state.scene?SC.amber:SC.border);\n      ctx.fillStyle=SC.dim; ctx.font=\"700 9px Inter\"; ctx.textAlign=\"left\"; ctx.fillText(String(s+1).padStart(3,''0''),x+10,yy+rh/2-4);\n      ctx.fillStyle=sc?SC.ink:SC.dim; ctx.font=\"800 12px Inter\"; ctx.fillText(sc?\"Cena \"+(s+1):\"Cena \"+(s+1)+\" (vazia)\",x+34,yy+rh/2-3);\n      ctx.fillStyle=sc?SC.green:SC.dim; ctx.font=\"700 9px Inter\"; ctx.fillText(sc?(\"armazenada \"+new Date(sc.ts).toLocaleTimeString().slice(0,5)):\"—\",x+34,yy+rh/2+11);\n      scrBtn(x+cw-146,yy+rh/2-13,66,26,\"STORE\",false,()=>{ state.scene=s; storeScene(s); paintRightRack(); },SC.amber);\n      scrBtn(x+cw-74,yy+rh/2-13,64,26,\"RECALL\",false,()=>{ state.scene=s; recallScene(s); paintRightRack(); },SC.green);\n      reg({x,y:yy,w:cw-150,h:rh,onDown:()=>{ state.scene=s; paintRightRack(); }});\n    }\n  }\n\n  /* ================= METER ================= */\n  function drawMeter(){\n    ctx.fillStyle=SC.mut; ctx.font=\"700 10px Inter\"; ctx.textAlign=\"left\"; ctx.fillText(\"METERS — 32 canais + Main master (toque um medidor p/ selecionar)\",10,13);\n    const n=N_CH,top=22,bot=H-22,gapx=3,bw=(W-20-40-(n-1)*gapx)/n;\n    for(let i=0;i<n;i++){ const ch=CH[i],x=10+i*(bw+gapx); const db=meterDbOf(i);\n      vmeter(x,top,bw,bot-top,db); ctx.fillStyle=ch.i===state.sel?SC.amber:SC.dim; ctx.font=\"700 7px Inter\"; ctx.textAlign=\"center\"; ctx.fillText(\"\"+(i+1),x+bw/2,bot+9);\n      reg({x,y:top,w:bw,h:bot-top,onDown:()=>selectChannel(i)});\n    }\n    const mx=W-30; vmeter(mx,top,12,bot-top,playing?masterLevelDb():-90); vmeter(mx+15,top,12,bot-top,playing?masterLevelDb()-2:-90);\n    ctx.fillStyle=SC.amber; ctx.font=\"700 8px Inter\"; ctx.textAlign=\"center\"; ctx.fillText(\"ST\",mx+13,bot+9);\n  }\n\n  function drawBridge(){ if(!MBW)return; mbx.clearRect(0,0,MBW,MBH); mbx.fillStyle=\"#07090c\"; mbx.fillRect(0,0,MBW,MBH);\n    const n=N_CH, pad=6, gap=2, bw=(MBW-pad*2-40-(n-1)*gap)/n, top=4, h=MBH-14;\n    for(let i=0;i<n;i++){ const ch=CH[i], x=pad+i*(bw+gap); const db=meterDbOf(i);\n      segMeter(x,top,bw,h,db);\n      mbx.fillStyle=ch.i===state.sel?\"#f4a02a\":\"#5f7b98\"; mbx.font=\"700 6px Inter\"; mbx.textAlign=\"center\"; mbx.fillText(\"\"+(i+1),x+bw/2,MBH-3); }\n    const mx=MBW-30; segMeter(mx,top,10,h,playing?masterLevelDb():-90); segMeter(mx+13,top,10,h,playing?masterLevelDb()-2:-90);\n    mbx.fillStyle=\"#ffd27a\"; mbx.font=\"700 6px Inter\"; mbx.textAlign=\"center\"; mbx.fillText(\"ST\",mx+11,MBH-3); }\n  function segMeter(x,y,w,h,db){ const segs=14; const t=clamp((db+60)/60,0,1), lit=Math.round(t*segs);\n    for(let s=0;s<segs;s++){ const sy=y+h-(s+1)*(h/segs)+1, sh=h/segs-1; const on=s<lit;\n      let col= s>=segs-2?\"#e0483f\": s>=segs-4?\"#e8c33a\":\"#37c86a\"; mbx.fillStyle=on?col:\"#111a12\"; mbx.fillRect(x,sy,w,sh); } }\n\n  /* ================= RIGHT RACK (user knobs / scene / user keys / monitor) ================= */\n  function buildRightRack(){\n    // user defined knobs A-D\n    const uk=$(\"#udknobs\"); const udNames=[\"A · MONITOR\",\"B · GAIN(sel)\",\"C · HPF(sel)\",\"D · REV RET\"];\n    uk.innerHTML=\"\";\n    for(let i=0;i<4;i++){ const w=document.createElement(\"div\"); w.className=\"kwrap\"; w.style.width=\"auto\";\n      w.innerHTML=`<div class=\"pk sm\" data-ud=\"${i}\"><div class=\"ring\" style=\"--led:#8fd8ff\"></div><div class=\"cap\"></div></div><div class=\"klbl\">${udNames[i]}</div><div class=\"kval\" data-udv=\"${i}\">—</div>`;\n      uk.appendChild(w); }\n    document.querySelectorAll(''.pk[data-ud]'').forEach(el=>{ const i=+el.dataset.ud;\n      const defs=[KDEF.monitor,KDEF.gain,KDEF.hpf,{min:0,max:1}];\n      wirePKDrag(el, ()=>udGet(i), v=>{ udSet(i,v); paintRightRack(); }, defs[i]); });\n    // scene buttons\n    $(\"#scStore\").onclick=()=>{ storeScene(state.scene); paintRightRack(); };\n    $(\"#scRecall\").onclick=()=>{ recallScene(state.scene); };\n    $(\"#scInc\").onclick=()=>{ state.scene=(state.scene+1)%N_SCENE; paintRightRack(); drawScreen(); };\n    $(\"#scDec\").onclick=()=>{ state.scene=(state.scene+N_SCENE-1)%N_SCENE; paintRightRack(); drawScreen(); };\n    $(\"#scUndo\").onclick=()=>{ toast(\"UNDO (última cena)\"); };\n    $(\"#scPrev\").onclick=()=>{ toast(\"PREVIEW: veja a cena sem aplicar\"); };\n    // user defined keys\n    const uks=$(\"#ukeys\"); uks.innerHTML=\"\";\n    UKEYS.forEach((k,i)=>{ const b=document.createElement(\"button\"); b.className=\"ukey\"; b.dataset.uk=i;\n      b.innerHTML=`<span>${k.label}</span>`; b.onclick=()=>k.act(b); uks.appendChild(b); });\n    // monitor/talkback\n    $(\"#tbKey\").onclick=()=>{ state.talkback=!state.talkback; $(\"#tbKey\").classList.toggle(\"lit\",state.talkback); toast(state.talkback?\"<b>TALKBACK</b> ON\":\"Talkback OFF\"); };\n    $(\"#dimKey\").onclick=()=>{ state.dim=!state.dim; $(\"#dimKey\").classList.toggle(\"on\",state.dim); applyMonitor(); toast(state.dim?\"MONITOR <b>DIM</b> -20dB\":\"Dim OFF\"); };\n  }\n  function udGet(i){ return [state.monitor, CH[state.sel].gain, CH[state.sel].hpf, state.fx.revMix][i]; }\n  function udSet(i,v){ if(i===0){state.monitor=Math.round(v);applyMonitor();}\n    else if(i===1){CH[state.sel].gain=v;applyChanAudio(state.sel);paintSelected();}\n    else if(i===2){CH[state.sel].hpf=Math.round(v);CH[state.sel].hpfOn=true;applyChanAudio(state.sel);paintSelected();}\n    else if(i===3){state.fx.revMix=v;applyFX();} drawScreen(); }\n  const UKEYS=[\n    {label:\"TALK\", act:b=>{ $(\"#tbKey\").click(); }},\n    {label:\"DIM\", act:b=>{ $(\"#dimKey\").click(); }},\n    {label:\"SCENE ▲\", act:b=>{ $(\"#scInc\").click(); }},\n    {label:\"SCENE ▼\", act:b=>{ $(\"#scDec\").click(); }},\n    {label:\"RECALL\", act:b=>{ recallScene(state.scene); }},\n    {label:\"METER\", act:b=>{ setMode(''meter''); }},\n    {label:\"EQ\", act:b=>{ setMode(''eq''); }},\n    {label:\"DYN\", act:b=>{ setMode(''gate''); }},\n    {label:\"SOF MIX1\", act:b=>{ engageSof(''mix'',0); }},\n    {label:\"MUTE1\", act:b=>{ state.muteActive[0]=!state.muteActive[0]; b.classList.toggle(\"on\",state.muteActive[0]); for(let i=0;i<N_CH;i++)if(CH[i].mute[0])applyChanAudio(i); paintBay(); }},\n    {label:\"OSC\", act:b=>{ b.classList.toggle(\"on\"); toast(\"Oscilador (didático)\"); }},\n    {label:\"TAP\", act:b=>{ toast(\"TAP tempo\"); }},\n    {label:\"CUE CLR\", act:b=>{ clearCue(); toast(\"CUE limpo\"); }},\n    {label:\"PANIC\", act:b=>{ CH.forEach(c=>{c.on=false;applyChanAudio(c.i);}); paintBay(); toast(\"PANIC: canais OFF\"); }},\n    {label:\"ALL ON\", act:b=>{ CH.forEach(c=>{c.on=true;applyChanAudio(c.i);}); paintBay(); toast(\"Todos ON\"); }},\n    {label:\"HOME\", act:b=>{ setMode(''selected''); }}\n  ];\n  function paintRightRack(){\n    $(\"#scnNum\").textContent=String(state.scene+1).padStart(3,''0'');\n    $(\"#scnName\").textContent=scenes[state.scene]?\"ARMAZENADA\":\"— VAZIA —\";\n    [\"monitor\",\"gain\",\"hpf\",\"rev\"].forEach((_,i)=>{ const defs=[KDEF.monitor,KDEF.gain,KDEF.hpf,{min:0,max:1,log:false}];\n      const el=$(`.pk[data-ud=\"${i}\"]`); if(el) setPK(el,defs[i],udGet(i));\n      const v=$(`[data-udv=\"${i}\"]`); if(v) v.textContent=[state.monitor+\"dB\",(CH[state.sel].gain>0?\"+\":\"\")+CH[state.sel].gain.toFixed(0),CH[state.sel].hpf+\"Hz\",Math.round(state.fx.revMix*100)+\"%\"][i]; });\n    $(\"#scMon\").textContent=state.monitor;\n  }\n\n  /* ================= MISSIONS ================= */\n  const missions=[\n    { t:''<b>Gain staging:</b> selecione o <b>canal 13</b> (botão SELECT) e ajuste o <b>GAIN</b> do preamp p/ a entrada picar perto de <b>−18 dBFS</b>.'',\n      ok:()=>{ const ch=CH[12]; return state.sel===12 && Math.abs(ch.src+ch.gain+18)<=2.5; } },\n    { t:''<b>Limpeza:</b> na seção CHANNEL STRIP, ative o <b>LOW CUT</b> do canal 13 em ~<b>100 Hz</b>.'',\n      ok:()=>{ const ch=CH[12]; return ch.hpfOn && Math.abs(ch.hpf-100)<=25; } },\n    { t:''<b>EQ:</b> abra a tela <b>EQ</b> e dê brilho — banda <b>HIGH</b> +3 dB ou mais (knob GAIN da banda HIGH).'',\n      ok:()=>{ const ch=CH[12]; return ch.eq[3].g>=3; } },\n    { t:''<b>Dinâmica:</b> abra <b>DYNAMICS</b>, ative o compressor e coloque o threshold ~<b>−18 dB</b>.'',\n      ok:()=>{ const ch=CH[12]; return ch.compOn && Math.abs(ch.compThr+18)<=4; } },\n    { t:''<b>Monitor:</b> selecione o master <b>BUS 1</b> (bay GROUP/BUS) p/ ligar <b>SENDS ON FADER</b> e mande o canal 13 a ~<b>−6 dB</b>.'',\n      ok:()=>{ const ch=CH[12]; return state.sof>=0 && state.sofType===''mix'' && state.sofBus===0 && ch.sendOn[0] && Math.abs(ch.sends[0]+6)<=3; } }\n  ];\n  let mi=0;\n  function paintMission(){ if(mi>=missions.length){ $(\"#mIdx\").textContent=\"CONCLUÍDO\"; $(\"#mTxt\").innerHTML=\"🎓 <b>Parabéns!</b> Fluxo completo no X32: gain → low cut → EQ → dinâmica → monitor.\"; $(\"#mSkip\").style.display=\"none\"; return; }\n    $(\"#mIdx\").textContent=\"MISSÃO \"+(mi+1)+\"/\"+missions.length; $(\"#mTxt\").innerHTML=missions[mi].t; }\n  function checkMissions(){ if(mi>=missions.length)return; try{ if(missions[mi].ok()){ mi++; toast(mi>=missions.length?\"Missões concluídas! 🎓\":\"Missão concluída! ✔\"); paintMission(); } }catch(e){} }\n  $(\"#mSkip\").onclick=()=>{ if(mi<missions.length){ mi++; paintMission(); } };\n  let toastT; function toast(msg){ const el=$(\"#toast\"); el.innerHTML=msg; el.classList.add(\"show\"); clearTimeout(toastT); toastT=setTimeout(()=>el.classList.remove(\"show\"),1800); }\n\n  /* ================= AUDIO ENGINE (preserved from working sim) ================= */\n  const SB=\"https://pshynylvvkhhohftouoe.supabase.co/storage/v1/object/public/media/\";\n  const sg=(n,c,f,p,h)=>({n,c,f,p,h});\n  const SONGS=[\n    {label:\"Pagodão — Tá Sozinha\", folder:\"mix-pagodao-tasozinha\", stems:[\n      sg(\"Bumbo\",\"#e0483f\",\"BB.mp3\",0,false),sg(\"Caixa\",\"#f97316\",\"CX.mp3\",0,true),sg(\"Surdo 1\",\"#f4a02a\",\"SD_1.mp3\",-8,false),sg(\"Surdo 2\",\"#eab308\",\"SD_2.mp3\",8,false),\n      sg(\"Chimbal\",\"#84cc16\",\"HH.mp3\",-15,true),sg(\"Repique\",\"#3ad07a\",\"REP.mp3\",12,true),sg(\"Rototom\",\"#14b8a6\",\"ROTANTAN.mp3\",-10,true),sg(\"Timbau\",\"#39c0e6\",\"TIMBAL.mp3\",10,true),\n      sg(\"Tom 1\",\"#3b82f6\",\"TOM1.mp3\",-6,true),sg(\"Tom 2\",\"#6366f1\",\"TOM2.mp3\",0,true),sg(\"Tom 3\",\"#8b5cf6\",\"TOM3.mp3\",6,true),sg(\"Conga Hi\",\"#a855f7\",\"CONGA_HI.mp3\",18,true),\n      sg(\"Conga Low\",\"#c084fc\",\"CONGA_LOW.mp3\",-18,true),sg(\"Baixo\",\"#3ad07a\",\"BASS-02.mp3\",0,false),sg(\"Guitarra\",\"#14b8a6\",\"GT-03.mp3\",-20,true),sg(\"Teclado 1\",\"#6366f1\",\"KEY_1-04.mp3\",15,false),\n      sg(\"Teclado 2\",\"#818cf8\",\"KEY_2-03.mp3\",-15,false)]},\n    {label:\"Forró — Thullio (c/ voz)\", folder:\"mix-forro-thullio\", stems:[\n      sg(\"Bumbo\",\"#e0483f\",\"1-KICK-glued.mp3\",0,false),sg(\"Caixa\",\"#f97316\",\"2-CX-glued.mp3\",0,true),sg(\"Esteira\",\"#f4a02a\",\"3-ESTEIRA-glued.mp3\",-10,true),sg(\"Caixa FX\",\"#eab308\",\"4-CX_FX-glued.mp3\",10,true),\n      sg(\"Chimbal\",\"#84cc16\",\"5-HH-glued.mp3\",-14,true),sg(\"Rototom\",\